// Generated from ecma262/spec.html — do not edit by hand.
const _sections = {"1":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">IdentifierReference[Yield, Await] :\n  Identifier\n  [~Yield] `yield`\n  [~Await] `await`\n\nBindingIdentifier[Yield, Await] :\n  Identifier\n  `yield`\n  `await`\n\nLabelIdentifier[Yield, Await] :\n  Identifier\n  [~Yield] `yield`\n  [~Await] `await`\n\nIdentifier :\n  IdentifierName but not ReservedWord</pre>\n\n    <emu-note>\n      <p><code>yield</code> and <code>await</code> are permitted as <emu-nt>BindingIdentifier</emu-nt> in the grammar, and prohibited with static semantics below, to prohibit automatic semicolon insertion in cases such as</p>\n      <pre><code class=\"javascript\">\n        let\n        await 0;\n      </code></pre>\n    </emu-note>\n\n    ","2":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">PrimaryExpression[Yield, Await] :\n  `this`\n  IdentifierReference[?Yield, ?Await]\n  Literal\n  ArrayLiteral[?Yield, ?Await]\n  ObjectLiteral[?Yield, ?Await]\n  FunctionExpression\n  ClassExpression[?Yield, ?Await]\n  GeneratorExpression\n  AsyncFunctionExpression\n  AsyncGeneratorExpression\n  RegularExpressionLiteral\n  TemplateLiteral[?Yield, ?Await, ~Tagged]\n  CoverParenthesizedExpressionAndArrowParameterList[?Yield, ?Await] #parencover\n\nCoverParenthesizedExpressionAndArrowParameterList[Yield, Await] :\n  `(` Expression[+In, ?Yield, ?Await] `)`\n  `(` Expression[+In, ?Yield, ?Await] `,` `)`\n  `(` `)`\n  `(` `...` BindingIdentifier[?Yield, ?Await] `)`\n  `(` `...` BindingPattern[?Yield, ?Await] `)`\n  `(` Expression[+In, ?Yield, ?Await] `,` `...` BindingIdentifier[?Yield, ?Await] `)`\n  `(` Expression[+In, ?Yield, ?Await] `,` `...` BindingPattern[?Yield, ?Await] `)`</pre>\n    <h2>Supplemental Syntax</h2>\n    <p>\n      When processing an instance of the production<br>\n      <pre class=\"emu-grammar\">PrimaryExpression[Yield, Await] : CoverParenthesizedExpressionAndArrowParameterList[?Yield, ?Await]</pre><br>\n      the interpretation of <emu-nt>CoverParenthesizedExpressionAndArrowParameterList</emu-nt> is refined using the following grammar:\n    </p>\n    <pre class=\"emu-grammar\">ParenthesizedExpression[Yield, Await] :\n  `(` Expression[+In, ?Yield, ?Await] `)`</pre>\n\n    ","3":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">MemberExpression[Yield, Await] :\n  PrimaryExpression[?Yield, ?Await]\n  MemberExpression[?Yield, ?Await] `[` Expression[+In, ?Yield, ?Await] `]`\n  MemberExpression[?Yield, ?Await] `.` IdentifierName\n  MemberExpression[?Yield, ?Await] TemplateLiteral[?Yield, ?Await, +Tagged]\n  SuperProperty[?Yield, ?Await]\n  MetaProperty\n  `new` MemberExpression[?Yield, ?Await] Arguments[?Yield, ?Await]\n  MemberExpression[?Yield, ?Await] `.` PrivateIdentifier\n\nSuperProperty[Yield, Await] :\n  `super` `[` Expression[+In, ?Yield, ?Await] `]`\n  `super` `.` IdentifierName\n\nMetaProperty :\n  NewTarget\n  ImportMeta\n\nNewTarget :\n  `new` `.` `target`\n\nImportMeta :\n  `import` `.` `meta`\n\nNewExpression[Yield, Await] :\n  MemberExpression[?Yield, ?Await]\n  `new` NewExpression[?Yield, ?Await]\n\nCallExpression[Yield, Await] :\n  CoverCallExpressionAndAsyncArrowHead[?Yield, ?Await] #callcover\n  SuperCall[?Yield, ?Await]\n  ImportCall[?Yield, ?Await]\n  CallExpression[?Yield, ?Await] Arguments[?Yield, ?Await]\n  CallExpression[?Yield, ?Await] `[` Expression[+In, ?Yield, ?Await] `]`\n  CallExpression[?Yield, ?Await] `.` IdentifierName\n  CallExpression[?Yield, ?Await] TemplateLiteral[?Yield, ?Await, +Tagged]\n  CallExpression[?Yield, ?Await] `.` PrivateIdentifier\n\nSuperCall[Yield, Await] :\n  `super` Arguments[?Yield, ?Await]\n\nImportCall[Yield, Await] :\n  `import` `(` AssignmentExpression[+In, ?Yield, ?Await] `,`? `)`\n  `import` `(` AssignmentExpression[+In, ?Yield, ?Await] `,` AssignmentExpression[+In, ?Yield, ?Await] `,`? `)`\n\nArguments[Yield, Await] :\n  `(` `)`\n  `(` ArgumentList[?Yield, ?Await] `)`\n  `(` ArgumentList[?Yield, ?Await] `,` `)`\n\nArgumentList[Yield, Await] :\n  AssignmentExpression[+In, ?Yield, ?Await]\n  `...` AssignmentExpression[+In, ?Yield, ?Await]\n  ArgumentList[?Yield, ?Await] `,` AssignmentExpression[+In, ?Yield, ?Await]\n  ArgumentList[?Yield, ?Await] `,` `...` AssignmentExpression[+In, ?Yield, ?Await]\n\nOptionalExpression[Yield, Await] :\n  MemberExpression[?Yield, ?Await] OptionalChain[?Yield, ?Await]\n  CallExpression[?Yield, ?Await] OptionalChain[?Yield, ?Await]\n  OptionalExpression[?Yield, ?Await] OptionalChain[?Yield, ?Await]\n\nOptionalChain[Yield, Await] :\n  `?.` Arguments[?Yield, ?Await]\n  `?.` `[` Expression[+In, ?Yield, ?Await] `]`\n  `?.` IdentifierName\n  `?.` TemplateLiteral[?Yield, ?Await, +Tagged]\n  `?.` PrivateIdentifier\n  OptionalChain[?Yield, ?Await] Arguments[?Yield, ?Await]\n  OptionalChain[?Yield, ?Await] `[` Expression[+In, ?Yield, ?Await] `]`\n  OptionalChain[?Yield, ?Await] `.` IdentifierName\n  OptionalChain[?Yield, ?Await] TemplateLiteral[?Yield, ?Await, +Tagged]\n  OptionalChain[?Yield, ?Await] `.` PrivateIdentifier\n\nLeftHandSideExpression[Yield, Await] :\n  NewExpression[?Yield, ?Await]\n  CallExpression[?Yield, ?Await]\n  OptionalExpression[?Yield, ?Await]</pre>\n    <h2>Supplemental Syntax</h2>\n    <p>\n      When processing an instance of the production<br>\n      <pre class=\"emu-grammar\">CallExpression : CoverCallExpressionAndAsyncArrowHead</pre><br>\n      the interpretation of <emu-nt>CoverCallExpressionAndAsyncArrowHead</emu-nt> is refined using the following grammar:\n    </p>\n    <pre class=\"emu-grammar\">CallMemberExpression[Yield, Await] :\n  MemberExpression[?Yield, ?Await] Arguments[?Yield, ?Await]</pre>\n\n    ","4":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">UpdateExpression[Yield, Await] :\n  LeftHandSideExpression[?Yield, ?Await]\n  LeftHandSideExpression[?Yield, ?Await] [no LineTerminator here] `++`\n  LeftHandSideExpression[?Yield, ?Await] [no LineTerminator here] `--`\n  `++` UnaryExpression[?Yield, ?Await]\n  `--` UnaryExpression[?Yield, ?Await]</pre>\n\n    ","5":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">UnaryExpression[Yield, Await] :\n  UpdateExpression[?Yield, ?Await]\n  `delete` UnaryExpression[?Yield, ?Await]\n  `void` UnaryExpression[?Yield, ?Await]\n  `typeof` UnaryExpression[?Yield, ?Await]\n  `+` UnaryExpression[?Yield, ?Await]\n  `-` UnaryExpression[?Yield, ?Await]\n  `~` UnaryExpression[?Yield, ?Await]\n  `!` UnaryExpression[?Yield, ?Await]\n  [+Await] AwaitExpression[?Yield]</pre>\n\n    ","6":"<h2>Syntax</h2>\n\n    <pre class=\"emu-grammar\">ExponentiationExpression[Yield, Await] :\n  UnaryExpression[?Yield, ?Await]\n  UpdateExpression[?Yield, ?Await] `**` ExponentiationExpression[?Yield, ?Await]</pre>\n\n    ","7":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">MultiplicativeExpression[Yield, Await] :\n  ExponentiationExpression[?Yield, ?Await]\n  MultiplicativeExpression[?Yield, ?Await] MultiplicativeOperator ExponentiationExpression[?Yield, ?Await]\n\nMultiplicativeOperator : one of\n  `*` `/` `%`</pre>\n    <emu-note>\n      <ul>\n        <li>The <code>*</code> operator performs multiplication, producing the product of its operands.</li>\n        <li>The <code>/</code> operator performs division, producing the quotient of its operands.</li>\n        <li>The <code>%</code> operator yields the remainder of its operands from an implied division.</li>\n      </ul>\n    </emu-note>\n\n    ","8":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">AdditiveExpression[Yield, Await] :\n  MultiplicativeExpression[?Yield, ?Await]\n  AdditiveExpression[?Yield, ?Await] `+` MultiplicativeExpression[?Yield, ?Await]\n  AdditiveExpression[?Yield, ?Await] `-` MultiplicativeExpression[?Yield, ?Await]</pre>\n\n    ","9":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">ShiftExpression[Yield, Await] :\n  AdditiveExpression[?Yield, ?Await]\n  ShiftExpression[?Yield, ?Await] `&lt;&lt;` AdditiveExpression[?Yield, ?Await]\n  ShiftExpression[?Yield, ?Await] `&gt;&gt;` AdditiveExpression[?Yield, ?Await]\n  ShiftExpression[?Yield, ?Await] `&gt;&gt;&gt;` AdditiveExpression[?Yield, ?Await]</pre>\n\n    ","10":"<emu-note>\n      <p>The result of evaluating a relational operator is always of type Boolean, reflecting whether the relationship named by the operator holds between its two operands.</p>\n    </emu-note>\n    <h2>Syntax</h2>\n    <pre class=\"emu-grammar\">RelationalExpression[In, Yield, Await] :\n  ShiftExpression[?Yield, ?Await]\n  RelationalExpression[?In, ?Yield, ?Await] `&lt;` ShiftExpression[?Yield, ?Await]\n  RelationalExpression[?In, ?Yield, ?Await] `&gt;` ShiftExpression[?Yield, ?Await]\n  RelationalExpression[?In, ?Yield, ?Await] `&lt;=` ShiftExpression[?Yield, ?Await]\n  RelationalExpression[?In, ?Yield, ?Await] `&gt;=` ShiftExpression[?Yield, ?Await]\n  RelationalExpression[?In, ?Yield, ?Await] `instanceof` ShiftExpression[?Yield, ?Await]\n  [+In] RelationalExpression[+In, ?Yield, ?Await] `in` ShiftExpression[?Yield, ?Await]\n  [+In] PrivateIdentifier `in` ShiftExpression[?Yield, ?Await]</pre>\n    <emu-note>\n      <p>The <sub>[In]</sub> grammar parameter is needed to avoid confusing the <code>in</code> operator in a relational expression with the <code>in</code> operator in a <code>for</code> statement.</p>\n    </emu-note>\n\n    ","11":"<emu-note>\n      <p>The result of evaluating an equality operator is always of type Boolean, reflecting whether the relationship named by the operator holds between its two operands.</p>\n    </emu-note>\n    <h2>Syntax</h2>\n    <pre class=\"emu-grammar\">EqualityExpression[In, Yield, Await] :\n  RelationalExpression[?In, ?Yield, ?Await]\n  EqualityExpression[?In, ?Yield, ?Await] `==` RelationalExpression[?In, ?Yield, ?Await]\n  EqualityExpression[?In, ?Yield, ?Await] `!=` RelationalExpression[?In, ?Yield, ?Await]\n  EqualityExpression[?In, ?Yield, ?Await] `===` RelationalExpression[?In, ?Yield, ?Await]\n  EqualityExpression[?In, ?Yield, ?Await] `!==` RelationalExpression[?In, ?Yield, ?Await]</pre>\n\n    ","12":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">BitwiseANDExpression[In, Yield, Await] :\n  EqualityExpression[?In, ?Yield, ?Await]\n  BitwiseANDExpression[?In, ?Yield, ?Await] `&amp;` EqualityExpression[?In, ?Yield, ?Await]\n\nBitwiseXORExpression[In, Yield, Await] :\n  BitwiseANDExpression[?In, ?Yield, ?Await]\n  BitwiseXORExpression[?In, ?Yield, ?Await] `^` BitwiseANDExpression[?In, ?Yield, ?Await]\n\nBitwiseORExpression[In, Yield, Await] :\n  BitwiseXORExpression[?In, ?Yield, ?Await]\n  BitwiseORExpression[?In, ?Yield, ?Await] `|` BitwiseXORExpression[?In, ?Yield, ?Await]</pre>\n\n    ","13":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">LogicalANDExpression[In, Yield, Await] :\n  BitwiseORExpression[?In, ?Yield, ?Await]\n  LogicalANDExpression[?In, ?Yield, ?Await] `&amp;&amp;` BitwiseORExpression[?In, ?Yield, ?Await]\n\nLogicalORExpression[In, Yield, Await] :\n  LogicalANDExpression[?In, ?Yield, ?Await]\n  LogicalORExpression[?In, ?Yield, ?Await] `||` LogicalANDExpression[?In, ?Yield, ?Await]\n\nCoalesceExpression[In, Yield, Await] :\n  CoalesceExpressionHead[?In, ?Yield, ?Await] `??` BitwiseORExpression[?In, ?Yield, ?Await]\n\nCoalesceExpressionHead[In, Yield, Await] :\n  CoalesceExpression[?In, ?Yield, ?Await]\n  BitwiseORExpression[?In, ?Yield, ?Await]\n\nShortCircuitExpression[In, Yield, Await] :\n  LogicalORExpression[?In, ?Yield, ?Await]\n  CoalesceExpression[?In, ?Yield, ?Await]</pre>\n    <emu-note>\n      <p>The value produced by a <code>&amp;&amp;</code> or <code>||</code> operator is not necessarily of type Boolean. The value produced will always be the value of one of the two operand expressions.</p>\n    </emu-note>\n\n    ","14":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">ConditionalExpression[In, Yield, Await] :\n  ShortCircuitExpression[?In, ?Yield, ?Await]\n  ShortCircuitExpression[?In, ?Yield, ?Await] `?` AssignmentExpression[+In, ?Yield, ?Await] `:` AssignmentExpression[?In, ?Yield, ?Await]</pre>\n    <emu-note>\n      <p>The grammar for a <emu-nt>ConditionalExpression</emu-nt> in ECMAScript is slightly different from that in C and Java, which each allow the second subexpression to be an <emu-nt>Expression</emu-nt> but restrict the third expression to be a <emu-nt>ConditionalExpression</emu-nt>. The motivation for this difference in ECMAScript is to allow an assignment expression to be governed by either arm of a conditional and to eliminate the confusing and fairly useless case of a comma expression as the centre expression.</p>\n    </emu-note>\n\n    ","15":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">AssignmentExpression[In, Yield, Await] :\n  ConditionalExpression[?In, ?Yield, ?Await]\n  [+Yield] YieldExpression[?In, ?Await]\n  ArrowFunction[?In, ?Yield, ?Await]\n  AsyncArrowFunction[?In, ?Yield, ?Await]\n  LeftHandSideExpression[?Yield, ?Await] `=` AssignmentExpression[?In, ?Yield, ?Await] #assignment\n  LeftHandSideExpression[?Yield, ?Await] AssignmentOperator AssignmentExpression[?In, ?Yield, ?Await]\n  LeftHandSideExpression[?Yield, ?Await] `&amp;&amp;=` AssignmentExpression[?In, ?Yield, ?Await]\n  LeftHandSideExpression[?Yield, ?Await] `||=` AssignmentExpression[?In, ?Yield, ?Await]\n  LeftHandSideExpression[?Yield, ?Await] `??=` AssignmentExpression[?In, ?Yield, ?Await]\n\n// emu-format ignore\nAssignmentOperator : one of\n  `*=` `/=` `%=` `+=` `-=` `&lt;&lt;=` `&gt;&gt;=` `&gt;&gt;&gt;=` `&amp;=` `^=` `|=` `**=`</pre>\n\n    ","16":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">Expression[In, Yield, Await] :\n  AssignmentExpression[?In, ?Yield, ?Await]\n  Expression[?In, ?Yield, ?Await] `,` AssignmentExpression[?In, ?Yield, ?Await]</pre>\n\n    ","":"","1.1":"<pre class=\"emu-grammar\">BindingIdentifier : Identifier</pre>\n      <ul>\n        <li>\n          It is a Syntax Error if IsStrict(this production) is <b>true</b> and the StringValue of <emu-nt>Identifier</emu-nt> is either <b>\"arguments\"</b> or <b>\"eval\"</b>.\n        </li>\n      </ul>\n      <pre class=\"emu-grammar\">IdentifierReference : `yield`\n\nBindingIdentifier : `yield`\n\nLabelIdentifier : `yield`</pre>\n      <ul>\n        <li>\n          It is a Syntax Error if IsStrict(this production) is <b>true</b>.\n        </li>\n      </ul>\n      <pre class=\"emu-grammar\">IdentifierReference : `await`\n\nBindingIdentifier : `await`\n\nLabelIdentifier : `await`</pre>\n      <ul>\n        <li>\n          It is a Syntax Error if the goal symbol of the syntactic grammar is <emu-nt>Module</emu-nt>.\n        </li>\n      </ul>\n      <pre class=\"emu-grammar\">BindingIdentifier[Yield, Await] : `yield`</pre>\n      <ul>\n        <li>\n          It is a Syntax Error if this production has a <sub>[Yield]</sub> parameter.\n        </li>\n      </ul>\n      <pre class=\"emu-grammar\">BindingIdentifier[Yield, Await] : `await`</pre>\n      <ul>\n        <li>\n          It is a Syntax Error if this production has an <sub>[Await]</sub> parameter.\n        </li>\n      </ul>\n      <pre class=\"emu-grammar\">IdentifierReference[Yield, Await] : Identifier\n\nBindingIdentifier[Yield, Await] : Identifier\n\nLabelIdentifier[Yield, Await] : Identifier</pre>\n      <ul>\n        <li>\n          It is a Syntax Error if this production has a <sub>[Yield]</sub> parameter and the StringValue of <emu-nt>Identifier</emu-nt> is <b>\"yield\"</b>.\n        </li>\n        <li>\n          It is a Syntax Error if this production has an <sub>[Await]</sub> parameter and the StringValue of <emu-nt>Identifier</emu-nt> is <b>\"await\"</b>.\n        </li>\n      </ul>\n      <pre class=\"emu-grammar\">Identifier : IdentifierName but not ReservedWord</pre>\n      <ul>\n        <li>\n          It is a Syntax Error if IsStrict(this phrase) is <b>true</b> and the StringValue of <emu-nt>IdentifierName</emu-nt> is one of <b>\"implements\"</b>, <b>\"interface\"</b>, <b>\"let\"</b>, <b>\"package\"</b>, <b>\"private\"</b>, <b>\"protected\"</b>, <b>\"public\"</b>, <b>\"static\"</b>, or <b>\"yield\"</b>.\n        </li>\n        <li>\n          It is a Syntax Error if the goal symbol of the syntactic grammar is <emu-nt>Module</emu-nt> and the StringValue of <emu-nt>IdentifierName</emu-nt> is <b>\"await\"</b>.\n        </li>\n        <li>\n          It is a Syntax Error if the StringValue of <emu-nt>IdentifierName</emu-nt> is the StringValue of any <emu-nt>ReservedWord</emu-nt> except for <code>yield</code> or <code>await</code>.\n        </li>\n      </ul>\n      <emu-note>\n        <p>The StringValue of <emu-nt>IdentifierName</emu-nt> normalizes any Unicode escape sequences in <emu-nt>IdentifierName</emu-nt> hence such escapes cannot be used to write an <emu-nt>Identifier</emu-nt> whose code point sequence is the same as a <emu-nt>ReservedWord</emu-nt>.</p>\n      </emu-note>\n    ","1.2":"<dl class=\"header\">\n      </dl>\n      <pre class=\"emu-grammar\">IdentifierName ::\n  IdentifierStart\n  IdentifierName IdentifierPart</pre>\n      <emu-alg><ol><li>Let <var>idTextUnescaped</var> be the IdentifierCodePoints of <emu-nt>IdentifierName</emu-nt>.</li><li>Return CodePointsToString(<var>idTextUnescaped</var>).</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">IdentifierReference : `yield`\n\nBindingIdentifier : `yield`\n\nLabelIdentifier : `yield`</pre>\n      <emu-alg><ol><li>Return <b>\"yield\"</b>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">IdentifierReference : `await`\n\nBindingIdentifier : `await`\n\nLabelIdentifier : `await`</pre>\n      <emu-alg><ol><li>Return <b>\"await\"</b>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">Identifier : IdentifierName but not ReservedWord</pre>\n      <emu-alg><ol><li>Return the StringValue of <emu-nt>IdentifierName</emu-nt>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">PrivateIdentifier ::\n  `#` IdentifierName</pre>\n      <emu-alg><ol><li>Return the string-concatenation of 0x0023 (NUMBER SIGN) and the StringValue of <emu-nt>IdentifierName</emu-nt>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">ModuleExportName : StringLiteral</pre>\n      <emu-alg><ol><li>Return the SV of <emu-nt>StringLiteral</emu-nt>.</li></ol></emu-alg>\n    ","1.3":"<pre class=\"emu-grammar\">IdentifierReference : Identifier</pre>\n      <emu-alg><ol><li>Return ? ResolveBinding(StringValue of <emu-nt>Identifier</emu-nt>).</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">IdentifierReference : `yield`</pre>\n      <emu-alg><ol><li>Return ? ResolveBinding(<b>\"yield\"</b>).</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">IdentifierReference : `await`</pre>\n      <emu-alg><ol><li>Return ? ResolveBinding(<b>\"await\"</b>).</li></ol></emu-alg>\n      <emu-note>\n        <p>The result of evaluating an <emu-nt>IdentifierReference</emu-nt> is always a value of type Reference.</p>\n      </emu-note>\n      <emu-note>\n        <p>In non-strict code, the keyword <code>yield</code> may be used as an identifier. Evaluating the <emu-nt>IdentifierReference</emu-nt> resolves the binding of <code>yield</code> as if it was an <emu-nt>Identifier</emu-nt>. Early Error restriction ensures that such an evaluation only can occur for non-strict code.</p>\n      </emu-note>\n    ","2.1":"","2.1.1":"<pre class=\"emu-grammar\">PrimaryExpression : `this`</pre>\n        <emu-alg><ol><li>Return ? ResolveThisBinding().</li></ol></emu-alg>\n      ","2.2":"<p>See <a href=\"/ecmascript-language-expressions#sec-identifiers\">13.1</a> for <emu-nt>IdentifierReference</emu-nt>.</p>\n    ","2.3":"<h2>Syntax</h2>\n      <pre class=\"emu-grammar\">Literal :\n  NullLiteral\n  BooleanLiteral\n  NumericLiteral\n  StringLiteral</pre>\n\n      ","2.3.1":"<pre class=\"emu-grammar\">Literal : NullLiteral</pre>\n        <emu-alg><ol><li>Return <b>null</b>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">Literal : BooleanLiteral</pre>\n        <emu-alg><ol><li>If <emu-nt>BooleanLiteral</emu-nt> is the token <code>false</code>, return <b>false</b>.</li><li>If <emu-nt>BooleanLiteral</emu-nt> is the token <code>true</code>, return <b>true</b>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">Literal : NumericLiteral</pre>\n        <emu-alg><ol><li>Return the NumericValue of <emu-nt>NumericLiteral</emu-nt> as defined in <a href=\"/ecmascript-language-lexical-grammar#sec-literals-numeric-literals\">12.9.3</a>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">Literal : StringLiteral</pre>\n        <emu-alg><ol><li>Return the SV of <emu-nt>StringLiteral</emu-nt> as defined in <a href=\"/ecmascript-language-lexical-grammar#sec-static-semantics-sv\">12.9.4.2</a>.</li></ol></emu-alg>\n      ","2.4":"<emu-note>\n        <p>An <emu-nt>ArrayLiteral</emu-nt> is an expression describing the initialization of an Array, using a list, of zero or more expressions each of which represents an array element, enclosed in square brackets. The elements need not be literals; they are evaluated each time the array initializer is evaluated.</p>\n      </emu-note>\n      <p>Array elements may be elided at the beginning, middle or end of the element list. Whenever a comma in the element list is not preceded by an <emu-nt>AssignmentExpression</emu-nt> (i.e., a comma at the beginning or after another comma), the missing array element contributes to the length of the Array and increases the index of subsequent elements. Elided array elements are not defined. If an element is elided at the end of an array, that element does not contribute to the length of the Array.</p>\n      <h2>Syntax</h2>\n      <pre class=\"emu-grammar\">ArrayLiteral[Yield, Await] :\n  `[` Elision? `]`\n  `[` ElementList[?Yield, ?Await] `]`\n  `[` ElementList[?Yield, ?Await] `,` Elision? `]`\n\nElementList[Yield, Await] :\n  Elision? AssignmentExpression[+In, ?Yield, ?Await]\n  Elision? SpreadElement[?Yield, ?Await]\n  ElementList[?Yield, ?Await] `,` Elision? AssignmentExpression[+In, ?Yield, ?Await]\n  ElementList[?Yield, ?Await] `,` Elision? SpreadElement[?Yield, ?Await]\n\nElision :\n  `,`\n  Elision `,`\n\nSpreadElement[Yield, Await] :\n  `...` AssignmentExpression[+In, ?Yield, ?Await]</pre>\n\n      ","2.4.1":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">Elision : `,`</pre>\n        <emu-alg><ol><li>Let <var>len</var> be <var>nextIndex</var> + 1.</li><li>Perform ? Set(<var>array</var>, <b>\"length\"</b>, 𝔽(<var>len</var>), <b>true</b>).</li><li>NOTE: The above step throws if <var>len</var> exceeds 2<sup>32</sup> - 1.</li><li>Return <var>len</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">Elision : Elision `,`</pre>\n        <emu-alg><ol><li>Return ? ArrayAccumulation of <emu-nt>Elision</emu-nt> with arguments <var>array</var> and (<var>nextIndex</var> + 1).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ElementList : Elision? AssignmentExpression</pre>\n        <emu-alg><ol><li>If <emu-nt>Elision</emu-nt> is present, then<ol><li>Set <var>nextIndex</var> to ? ArrayAccumulation of <emu-nt>Elision</emu-nt> with arguments <var>array</var> and <var>nextIndex</var>.</li></ol></li><li>Let <var>initResult</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>initValue</var> be ? GetValue(<var>initResult</var>).</li><li>Perform ! CreateDataPropertyOrThrow(<var>array</var>, ! ToString(𝔽(<var>nextIndex</var>)), <var>initValue</var>).</li><li>Return <var>nextIndex</var> + 1.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ElementList : Elision? SpreadElement</pre>\n        <emu-alg><ol><li>If <emu-nt>Elision</emu-nt> is present, then<ol><li>Set <var>nextIndex</var> to ? ArrayAccumulation of <emu-nt>Elision</emu-nt> with arguments <var>array</var> and <var>nextIndex</var>.</li></ol></li><li>Return ? ArrayAccumulation of <emu-nt>SpreadElement</emu-nt> with arguments <var>array</var> and <var>nextIndex</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ElementList : ElementList `,` Elision? AssignmentExpression</pre>\n        <emu-alg><ol><li>Set <var>nextIndex</var> to ? ArrayAccumulation of the derived <emu-nt>ElementList</emu-nt> with arguments <var>array</var> and <var>nextIndex</var>.</li><li>If <emu-nt>Elision</emu-nt> is present, then<ol><li>Set <var>nextIndex</var> to ? ArrayAccumulation of <emu-nt>Elision</emu-nt> with arguments <var>array</var> and <var>nextIndex</var>.</li></ol></li><li>Let <var>initResult</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>initValue</var> be ? GetValue(<var>initResult</var>).</li><li>Perform ! CreateDataPropertyOrThrow(<var>array</var>, ! ToString(𝔽(<var>nextIndex</var>)), <var>initValue</var>).</li><li>Return <var>nextIndex</var> + 1.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ElementList : ElementList `,` Elision? SpreadElement</pre>\n        <emu-alg><ol><li>Set <var>nextIndex</var> to ? ArrayAccumulation of the derived <emu-nt>ElementList</emu-nt> with arguments <var>array</var> and <var>nextIndex</var>.</li><li>If <emu-nt>Elision</emu-nt> is present, then<ol><li>Set <var>nextIndex</var> to ? ArrayAccumulation of <emu-nt>Elision</emu-nt> with arguments <var>array</var> and <var>nextIndex</var>.</li></ol></li><li>Return ? ArrayAccumulation of <emu-nt>SpreadElement</emu-nt> with arguments <var>array</var> and <var>nextIndex</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">SpreadElement : `...` AssignmentExpression</pre>\n        <emu-alg><ol><li>Let <var>spreadRef</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>spreadObj</var> be ? GetValue(<var>spreadRef</var>).</li><li>Let <var>iteratorRecord</var> be ? GetIterator(<var>spreadObj</var>, <emu-const>sync</emu-const>).</li><li>Repeat,<ol><li>Let <var>next</var> be ? IteratorStepValue(<var>iteratorRecord</var>).</li><li>If <var>next</var> is <emu-const>done</emu-const>, return <var>nextIndex</var>.</li><li>Perform ! CreateDataPropertyOrThrow(<var>array</var>, ! ToString(𝔽(<var>nextIndex</var>)), <var>next</var>).</li><li>Set <var>nextIndex</var> to <var>nextIndex</var> + 1.</li></ol></li></ol></emu-alg>\n        <emu-note>\n          <p>CreateDataPropertyOrThrow is used to ensure that own properties are defined for the array even if the standard built-in Array prototype object has been modified in a manner that would preclude the creation of new own properties using [[Set]].</p>\n        </emu-note>\n      ","2.4.2":"<pre class=\"emu-grammar\">ArrayLiteral : `[` Elision? `]`</pre>\n        <emu-alg><ol><li>Let <var>array</var> be ! ArrayCreate(0).</li><li>If <emu-nt>Elision</emu-nt> is present, then<ol><li>Perform ? ArrayAccumulation of <emu-nt>Elision</emu-nt> with arguments <var>array</var> and 0.</li></ol></li><li>Return <var>array</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ArrayLiteral : `[` ElementList `]`</pre>\n        <emu-alg><ol><li>Let <var>array</var> be ! ArrayCreate(0).</li><li>Perform ? ArrayAccumulation of <emu-nt>ElementList</emu-nt> with arguments <var>array</var> and 0.</li><li>Return <var>array</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ArrayLiteral : `[` ElementList `,` Elision? `]`</pre>\n        <emu-alg><ol><li>Let <var>array</var> be ! ArrayCreate(0).</li><li>Let <var>nextIndex</var> be ? ArrayAccumulation of <emu-nt>ElementList</emu-nt> with arguments <var>array</var> and 0.</li><li>If <emu-nt>Elision</emu-nt> is present, then<ol><li>Perform ? ArrayAccumulation of <emu-nt>Elision</emu-nt> with arguments <var>array</var> and <var>nextIndex</var>.</li></ol></li><li>Return <var>array</var>.</li></ol></emu-alg>\n      ","2.5":"<emu-note>\n        <p>An object initializer is an expression describing the initialization of an Object, written in a form resembling a literal. It is a list of zero or more pairs of property keys and associated values, enclosed in curly brackets. The values need not be literals; they are evaluated each time the object initializer is evaluated.</p>\n      </emu-note>\n      <h2>Syntax</h2>\n      <pre class=\"emu-grammar\">ObjectLiteral[Yield, Await] :\n  `{` `}`\n  `{` PropertyDefinitionList[?Yield, ?Await] `}`\n  `{` PropertyDefinitionList[?Yield, ?Await] `,` `}`\n\nPropertyDefinitionList[Yield, Await] :\n  PropertyDefinition[?Yield, ?Await]\n  PropertyDefinitionList[?Yield, ?Await] `,` PropertyDefinition[?Yield, ?Await]\n\nPropertyDefinition[Yield, Await] :\n  IdentifierReference[?Yield, ?Await]\n  CoverInitializedName[?Yield, ?Await]\n  PropertyName[?Yield, ?Await] `:` AssignmentExpression[+In, ?Yield, ?Await]\n  MethodDefinition[?Yield, ?Await]\n  `...` AssignmentExpression[+In, ?Yield, ?Await]\n\nPropertyName[Yield, Await] :\n  LiteralPropertyName\n  ComputedPropertyName[?Yield, ?Await]\n\nLiteralPropertyName :\n  IdentifierName\n  StringLiteral\n  NumericLiteral\n\nComputedPropertyName[Yield, Await] :\n  `[` AssignmentExpression[+In, ?Yield, ?Await] `]`\n\nCoverInitializedName[Yield, Await] :\n  IdentifierReference[?Yield, ?Await] Initializer[+In, ?Yield, ?Await]\n\nInitializer[In, Yield, Await] :\n  `=` AssignmentExpression[?In, ?Yield, ?Await]</pre>\n      <emu-note>\n        <p><emu-nt>MethodDefinition</emu-nt> is defined in <a href=\"/ecmascript-language-functions-and-classes#sec-method-definitions\">15.4</a>.</p>\n      </emu-note>\n      <emu-note>\n        <p>In certain contexts, <emu-nt>ObjectLiteral</emu-nt> is used as a cover grammar for a more restricted secondary grammar. The <emu-nt>CoverInitializedName</emu-nt> production is necessary to fully cover these secondary grammars. However, use of this production results in an early Syntax Error in normal contexts where an actual <emu-nt>ObjectLiteral</emu-nt> is expected.</p>\n      </emu-note>\n\n      ","2.5.1":"<pre class=\"emu-grammar\">PropertyDefinition : MethodDefinition</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if HasDirectSuper of <emu-nt>MethodDefinition</emu-nt> is <b>true</b>.\n          </li>\n          <li>\n            It is a Syntax Error if the PrivateBoundIdentifiers of <emu-nt>MethodDefinition</emu-nt> is not empty.\n          </li>\n        </ul>\n        <p>In addition to describing an actual object initializer the <emu-nt>ObjectLiteral</emu-nt> productions are also used as a cover grammar for <emu-nt>ObjectAssignmentPattern</emu-nt> and may be recognized as part of a <emu-nt>CoverParenthesizedExpressionAndArrowParameterList</emu-nt>. When <emu-nt>ObjectLiteral</emu-nt> appears in a context where <emu-nt>ObjectAssignmentPattern</emu-nt> is required the following Early Error rules are <b>not</b> applied. In addition, they are not applied when initially parsing a <emu-nt>CoverParenthesizedExpressionAndArrowParameterList</emu-nt> or <emu-nt>CoverCallExpressionAndAsyncArrowHead</emu-nt>.</p>\n        <pre class=\"emu-grammar\">PropertyDefinition : CoverInitializedName</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if any source text is matched by this production.\n          </li>\n        </ul>\n        <emu-note>\n          <p>This production exists so that <emu-nt>ObjectLiteral</emu-nt> can serve as a cover grammar for <emu-nt>ObjectAssignmentPattern</emu-nt>. It cannot occur in an actual object initializer.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\">ObjectLiteral :\n  `{` PropertyDefinitionList `}`\n  `{` PropertyDefinitionList `,` `}`</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if the PropertyNameList of <emu-nt>PropertyDefinitionList</emu-nt> contains any duplicate entries for <b>\"__proto__\"</b> and at least two of those entries were obtained from productions of the form <code class=\"emu-grammar\">PropertyDefinition : PropertyName `:` AssignmentExpression</code>. This rule is not applied if this <emu-nt>ObjectLiteral</emu-nt> is contained within a <emu-nt>Script</emu-nt> that is being parsed for ParseJSON (see step step-json-parse-parse of ParseJSON).\n          </li>\n        </ul>\n        <emu-note>\n          <p>The List returned by PropertyNameList does not include property names defined using a <emu-nt>ComputedPropertyName</emu-nt>.</p>\n        </emu-note>\n      ","2.5.2":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">PropertyName : LiteralPropertyName</pre>\n        <emu-alg><ol><li>Return <b>false</b>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">PropertyName : ComputedPropertyName</pre>\n        <emu-alg><ol><li>Return <b>true</b>.</li></ol></emu-alg>\n      ","2.5.3":"<dl class=\"header\">\n        </dl>\n\n        <pre class=\"emu-grammar\">ObjectLiteral : `{` `}`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n\n        <pre class=\"emu-grammar\">PropertyDefinitionList : PropertyDefinition</pre>\n        <emu-alg><ol><li>Return « <emu-nt>PropertyDefinition</emu-nt> ».</li></ol></emu-alg>\n\n        <pre class=\"emu-grammar\">PropertyDefinitionList : PropertyDefinitionList `,` PropertyDefinition</pre>\n        <emu-alg><ol><li>Let <var>head</var> be the PropertyDefinitionNodes of the derived <emu-nt>PropertyDefinitionList</emu-nt>.</li><li>Return the list-concatenation of <var>head</var> and « <emu-nt>PropertyDefinition</emu-nt> ».</li></ol></emu-alg>\n      ","2.5.4":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">PropertyDefinitionList : PropertyDefinition</pre>\n        <emu-alg><ol><li>Let <var>propName</var> be the PropName of <emu-nt>PropertyDefinition</emu-nt>.</li><li>If <var>propName</var> is <emu-const>empty</emu-const>, return a new empty List.</li><li>Return « <var>propName</var> ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">PropertyDefinitionList : PropertyDefinitionList `,` PropertyDefinition</pre>\n        <emu-alg><ol><li>Let <var>list</var> be the PropertyNameList of <emu-nt>PropertyDefinitionList</emu-nt>.</li><li>Let <var>propName</var> be the PropName of <emu-nt>PropertyDefinition</emu-nt>.</li><li>If <var>propName</var> is <emu-const>empty</emu-const>, return <var>list</var>.</li><li>Return the list-concatenation of <var>list</var> and « <var>propName</var> ».</li></ol></emu-alg>\n      ","2.5.5":"<pre class=\"emu-grammar\">ObjectLiteral : `{` `}`</pre>\n        <emu-alg><ol><li>Return OrdinaryObjectCreate(<code class=\"emu-intrinsic\">%Object.prototype%</code>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ObjectLiteral :\n  `{` PropertyDefinitionList `}`\n  `{` PropertyDefinitionList `,` `}`</pre>\n        <emu-alg><ol><li>Let <var>obj</var> be OrdinaryObjectCreate(<code class=\"emu-intrinsic\">%Object.prototype%</code>).</li><li>Perform ? PropertyDefinitionEvaluation of <emu-nt>PropertyDefinitionList</emu-nt> with argument <var>obj</var>.</li><li>Return <var>obj</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">LiteralPropertyName : IdentifierName</pre>\n        <emu-alg><ol><li>Return the StringValue of <emu-nt>IdentifierName</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">LiteralPropertyName : StringLiteral</pre>\n        <emu-alg><ol><li>Return the SV of <emu-nt>StringLiteral</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">LiteralPropertyName : NumericLiteral</pre>\n        <emu-alg><ol><li>Let <var>nbr</var> be the NumericValue of <emu-nt>NumericLiteral</emu-nt>.</li><li>Return ! ToString(<var>nbr</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ComputedPropertyName : `[` AssignmentExpression `]`</pre>\n        <emu-alg><ol><li>Let <var>exprValue</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>propName</var> be ? GetValue(<var>exprValue</var>).</li><li>Return ? ToPropertyKey(<var>propName</var>).</li></ol></emu-alg>\n      ","2.5.6":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">PropertyDefinitionList : PropertyDefinitionList `,` PropertyDefinition</pre>\n        <emu-alg><ol><li>Perform ? PropertyDefinitionEvaluation of <emu-nt>PropertyDefinitionList</emu-nt> with argument <var>object</var>.</li><li>Perform ? PropertyDefinitionEvaluation of <emu-nt>PropertyDefinition</emu-nt> with argument <var>object</var>.</li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">PropertyDefinition : `...` AssignmentExpression</pre>\n        <emu-alg><ol><li>Let <var>exprValue</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>fromValue</var> be ? GetValue(<var>exprValue</var>).</li><li>Let <var>excludedNames</var> be a new empty List.</li><li>Perform ? CopyDataProperties(<var>object</var>, <var>fromValue</var>, <var>excludedNames</var>).</li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">PropertyDefinition : IdentifierReference</pre>\n        <emu-alg><ol><li>Let <var>propName</var> be the StringValue of <emu-nt>IdentifierReference</emu-nt>.</li><li>Let <var>exprValue</var> be ? Evaluation of <emu-nt>IdentifierReference</emu-nt>.</li><li>Let <var>propValue</var> be ? GetValue(<var>exprValue</var>).</li><li>Assert: <var>object</var> is an ordinary, extensible object with no non-configurable properties.</li><li>Perform ! CreateDataPropertyOrThrow(<var>object</var>, <var>propName</var>, <var>propValue</var>).</li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">PropertyDefinition : PropertyName `:` AssignmentExpression</pre>\n        <emu-alg><ol><li>Let <var>propertyKey</var> be ? Evaluation of <emu-nt>PropertyName</emu-nt>.</li><li>If this <emu-nt>PropertyDefinition</emu-nt> is contained within a <emu-nt>Script</emu-nt> that is being evaluated for ParseJSON (see step step-json-parse-eval of ParseJSON), then<ol><li>Let <var>isProtoSetter</var> be <b>false</b>.</li></ol></li><li>Else if <var>propertyKey</var> is <b>\"__proto__\"</b> and IsComputedPropertyKey of <emu-nt>PropertyName</emu-nt> is <b>false</b>, then<ol><li>Let <var>isProtoSetter</var> be <b>true</b>.</li></ol></li><li>Else,<ol><li>Let <var>isProtoSetter</var> be <b>false</b>.</li></ol></li><li>If IsAnonymousFunctionDefinition(<emu-nt>AssignmentExpression</emu-nt>) is <b>true</b> and <var>isProtoSetter</var> is <b>false</b>, then<ol><li>Let <var>propValue</var> be ? NamedEvaluation of <emu-nt>AssignmentExpression</emu-nt> with argument <var>propertyKey</var>.</li></ol></li><li>Else,<ol><li>Let <var>exprValueRef</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>propValue</var> be ? GetValue(<var>exprValueRef</var>).</li></ol></li><li>If <var>isProtoSetter</var> is <b>true</b>, then<ol><li>If <var>propValue</var> is an Object or <var>propValue</var> is <b>null</b>, then<ol><li>Perform ! <emu-meta effects=\"user-code\"><var>object</var>.[[SetPrototypeOf]](<var>propValue</var>)</emu-meta>.</li></ol></li><li>Return <emu-const>unused</emu-const>.</li></ol></li><li>Assert: <var>object</var> is an ordinary, extensible object with no non-configurable properties.</li><li>Perform ! CreateDataPropertyOrThrow(<var>object</var>, <var>propertyKey</var>, <var>propValue</var>).</li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">PropertyDefinition : MethodDefinition</pre>\n        <emu-alg><ol><li>Perform ? MethodDefinitionEvaluation of <emu-nt>MethodDefinition</emu-nt> with arguments <var>object</var> and <b>true</b>.</li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n      ","2.6":"<p>See <a href=\"/ecmascript-language-functions-and-classes#sec-function-definitions\">15.2</a> for <code class=\"emu-grammar\">PrimaryExpression : FunctionExpression</code>.</p>\n      <p>See <a href=\"/ecmascript-language-functions-and-classes#sec-generator-function-definitions\">15.5</a> for <code class=\"emu-grammar\">PrimaryExpression : GeneratorExpression</code>.</p>\n      <p>See <a href=\"/ecmascript-language-functions-and-classes#sec-class-definitions\">15.7</a> for <code class=\"emu-grammar\">PrimaryExpression : ClassExpression</code>.</p>\n      <p>See <a href=\"/ecmascript-language-functions-and-classes#sec-async-function-definitions\">15.8</a> for <code class=\"emu-grammar\">PrimaryExpression : AsyncFunctionExpression</code>.</p>\n      <p>See <a href=\"/ecmascript-language-functions-and-classes#sec-async-generator-function-definitions\">15.6</a> for <code class=\"emu-grammar\">PrimaryExpression : AsyncGeneratorExpression</code>.</p>\n    ","2.7":"<h2>Syntax</h2>\n      <p>See <a href=\"/ecmascript-language-lexical-grammar#sec-literals-regular-expression-literals\">12.9.5</a>.</p>\n\n      ","2.7.1":"<pre class=\"emu-grammar\">PrimaryExpression : RegularExpressionLiteral</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if IsValidRegularExpressionLiteral(<emu-nt>RegularExpressionLiteral</emu-nt>) is <b>false</b>.\n          </li>\n        </ul>\n      ","2.7.2":"<dl class=\"header\">\n          <dt>description</dt>\n          <dd>It determines if its argument is a valid regular expression literal.</dd>\n        </dl>\n        <emu-alg><ol><li>Let <var>flags</var> be the FlagText of <var>literal</var>.</li><li>If <var>flags</var> contains any code points other than <code>d</code>, <code>g</code>, <code>i</code>, <code>m</code>, <code>s</code>, <code>u</code>, <code>v</code>, or <code>y</code>, return <b>false</b>.</li><li>If <var>flags</var> contains any code point more than once, return <b>false</b>.</li><li>If <var>flags</var> contains <code>u</code>, let <var>u</var> be <b>true</b>; else let <var>u</var> be <b>false</b>.</li><li>If <var>flags</var> contains <code>v</code>, let <var>v</var> be <b>true</b>; else let <var>v</var> be <b>false</b>.</li><li>Let <var>patternText</var> be the BodyText of <var>literal</var>.</li><li>If <var>u</var> is <b>false</b> and <var>v</var> is <b>false</b>, then<ol><li>Let <var>stringValue</var> be CodePointsToString(<var>patternText</var>).</li><li>Set <var>patternText</var> to the sequence of code points resulting from interpreting each of the 16-bit elements of <var>stringValue</var> as a Unicode BMP code point. UTF-16 decoding is not applied to the elements.</li></ol></li><li>Let <var>parseResult</var> be ParsePattern(<var>patternText</var>, <var>u</var>, <var>v</var>).</li><li>If <var>parseResult</var> is a Parse Node, return <b>true</b>.</li><li>Return <b>false</b>.</li></ol></emu-alg>\n      ","2.7.3":"<pre class=\"emu-grammar\">PrimaryExpression : RegularExpressionLiteral</pre>\n        <emu-alg><ol><li>Let <var>pattern</var> be CodePointsToString(BodyText of <emu-nt>RegularExpressionLiteral</emu-nt>).</li><li>Let <var>flags</var> be CodePointsToString(FlagText of <emu-nt>RegularExpressionLiteral</emu-nt>).</li><li>Return ! RegExpCreate(<var>pattern</var>, <var>flags</var>).</li></ol></emu-alg>\n      ","2.8":"<h2>Syntax</h2>\n      <pre class=\"emu-grammar\">TemplateLiteral[Yield, Await, Tagged] :\n  NoSubstitutionTemplate\n  SubstitutionTemplate[?Yield, ?Await, ?Tagged]\n\nSubstitutionTemplate[Yield, Await, Tagged] :\n  TemplateHead Expression[+In, ?Yield, ?Await] TemplateSpans[?Yield, ?Await, ?Tagged]\n\nTemplateSpans[Yield, Await, Tagged] :\n  TemplateTail\n  TemplateMiddleList[?Yield, ?Await, ?Tagged] TemplateTail\n\nTemplateMiddleList[Yield, Await, Tagged] :\n  TemplateMiddle Expression[+In, ?Yield, ?Await]\n  TemplateMiddleList[?Yield, ?Await, ?Tagged] TemplateMiddle Expression[+In, ?Yield, ?Await]</pre>\n\n      ","2.8.1":"<pre class=\"emu-grammar\">TemplateLiteral[Yield, Await, Tagged] : NoSubstitutionTemplate</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if the <sub>[Tagged]</sub> parameter was not set and <emu-nt>NoSubstitutionTemplate</emu-nt> Contains <emu-nt>NotEscapeSequence</emu-nt>.\n          </li>\n        </ul>\n\n        <pre class=\"emu-grammar\">TemplateLiteral[Yield, Await, Tagged] : SubstitutionTemplate[?Yield, ?Await, ?Tagged]</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if the number of elements in the TemplateStrings of <emu-nt>TemplateLiteral</emu-nt> with argument <b>false</b> is greater than or equal to 2<sup>32</sup>.\n          </li>\n        </ul>\n\n        <pre class=\"emu-grammar\">SubstitutionTemplate[Yield, Await, Tagged] : TemplateHead Expression[+In, ?Yield, ?Await] TemplateSpans[?Yield, ?Await, ?Tagged]</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if the <sub>[Tagged]</sub> parameter was not set and <emu-nt>TemplateHead</emu-nt> Contains <emu-nt>NotEscapeSequence</emu-nt>.\n          </li>\n        </ul>\n\n        <pre class=\"emu-grammar\">TemplateSpans[Yield, Await, Tagged] : TemplateTail</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if the <sub>[Tagged]</sub> parameter was not set and <emu-nt>TemplateTail</emu-nt> Contains <emu-nt>NotEscapeSequence</emu-nt>.\n          </li>\n        </ul>\n\n        <pre class=\"emu-grammar\">TemplateMiddleList[Yield, Await, Tagged] :\n  TemplateMiddle Expression[+In, ?Yield, ?Await]\n  TemplateMiddleList[?Yield, ?Await, ?Tagged] TemplateMiddle Expression[+In, ?Yield, ?Await]</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if the <sub>[Tagged]</sub> parameter was not set and <emu-nt>TemplateMiddle</emu-nt> Contains <emu-nt>NotEscapeSequence</emu-nt>.\n          </li>\n        </ul>\n      ","2.8.2":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">TemplateLiteral : NoSubstitutionTemplate</pre>\n        <emu-alg><ol><li>Return « TemplateString(<emu-nt>NoSubstitutionTemplate</emu-nt>, <var>raw</var>) ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">SubstitutionTemplate : TemplateHead Expression TemplateSpans</pre>\n        <emu-alg><ol><li>Let <var>head</var> be « TemplateString(<emu-nt>TemplateHead</emu-nt>, <var>raw</var>) ».</li><li>Let <var>tail</var> be the TemplateStrings of <emu-nt>TemplateSpans</emu-nt> with argument <var>raw</var>.</li><li>Return the list-concatenation of <var>head</var> and <var>tail</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">TemplateSpans : TemplateTail</pre>\n        <emu-alg><ol><li>Return « TemplateString(<emu-nt>TemplateTail</emu-nt>, <var>raw</var>) ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">TemplateSpans : TemplateMiddleList TemplateTail</pre>\n        <emu-alg><ol><li>Let <var>middle</var> be the TemplateStrings of <emu-nt>TemplateMiddleList</emu-nt> with argument <var>raw</var>.</li><li>Let <var>tail</var> be « TemplateString(<emu-nt>TemplateTail</emu-nt>, <var>raw</var>) ».</li><li>Return the list-concatenation of <var>middle</var> and <var>tail</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">TemplateMiddleList : TemplateMiddle Expression</pre>\n        <emu-alg><ol><li>Return « TemplateString(<emu-nt>TemplateMiddle</emu-nt>, <var>raw</var>) ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">TemplateMiddleList : TemplateMiddleList TemplateMiddle Expression</pre>\n        <emu-alg><ol><li>Let <var>front</var> be the TemplateStrings of <emu-nt>TemplateMiddleList</emu-nt> with argument <var>raw</var>.</li><li>Let <var>last</var> be « TemplateString(<emu-nt>TemplateMiddle</emu-nt>, <var>raw</var>) ».</li><li>Return the list-concatenation of <var>front</var> and <var>last</var>.</li></ol></emu-alg>\n      ","2.8.3":"<dl class=\"header\">\n        </dl>\n        <emu-alg><ol><li>If <var>raw</var> is <b>true</b>, then<ol><li>Let <var>string</var> be the TRV of <var>templateToken</var>.</li></ol></li><li>Else,<ol><li>Let <var>string</var> be the TV of <var>templateToken</var>.</li></ol></li><li>Return <var>string</var>.</li></ol></emu-alg>\n        <emu-note>\n          <p>This operation returns <b>undefined</b> if <var>raw</var> is <b>false</b> and <var>templateToken</var> contains a <emu-nt>NotEscapeSequence</emu-nt>. In all other cases, it returns a String.</p>\n        </emu-note>\n      ","2.8.4":"<dl class=\"header\">\n        </dl>\n        <emu-alg><ol><li>Let <var>realm</var> be the current Realm Record.</li><li>Let <var>templateRegistry</var> be <var>realm</var>.[[TemplateMap]].</li><li>For each element <var>e</var> of <var>templateRegistry</var>, do<ol><li>If <var>e</var>.[[Site]] is the same Parse Node as <var>templateLiteral</var>, then<ol><li>Return <var>e</var>.[[Array]].</li></ol></li></ol></li><li>Let <var>rawStrings</var> be the TemplateStrings of <var>templateLiteral</var> with argument <b>true</b>.</li><li>Assert: <var>rawStrings</var> is a List of Strings.</li><li>Let <var>cookedStrings</var> be the TemplateStrings of <var>templateLiteral</var> with argument <b>false</b>.</li><li>Let <var>count</var> be the number of elements in the List <var>cookedStrings</var>.</li><li>Assert: <var>count</var> ≤ 2<sup>32</sup> - 1.</li><li>Let <var>template</var> be ! ArrayCreate(<var>count</var>).</li><li>Let <var>rawObj</var> be ! ArrayCreate(<var>count</var>).</li><li>Let <var>index</var> be 0.</li><li>Repeat, while <var>index</var> &lt; <var>count</var>,<ol><li>Let <var>propertyKey</var> be ! ToString(𝔽(<var>index</var>)).</li><li>Let <var>cookedValue</var> be <var>cookedStrings</var>[<var>index</var>].</li><li>Perform ! DefinePropertyOrThrow(<var>template</var>, <var>propertyKey</var>, PropertyDescriptor { [[Value]]: <var>cookedValue</var>, [[Writable]]: <b>false</b>, [[Enumerable]]: <b>true</b>, [[Configurable]]: <b>false</b> }).</li><li>Let <var>rawValue</var> be the String value <var>rawStrings</var>[<var>index</var>].</li><li>Perform ! DefinePropertyOrThrow(<var>rawObj</var>, <var>propertyKey</var>, PropertyDescriptor { [[Value]]: <var>rawValue</var>, [[Writable]]: <b>false</b>, [[Enumerable]]: <b>true</b>, [[Configurable]]: <b>false</b> }).</li><li>Set <var>index</var> to <var>index</var> + 1.</li></ol></li><li>Perform ! SetIntegrityLevel(<var>rawObj</var>, <emu-const>frozen</emu-const>).</li><li>Perform ! DefinePropertyOrThrow(<var>template</var>, <b>\"raw\"</b>, PropertyDescriptor { [[Value]]: <var>rawObj</var>, [[Writable]]: <b>false</b>, [[Enumerable]]: <b>false</b>, [[Configurable]]: <b>false</b> }).</li><li>Perform ! SetIntegrityLevel(<var>template</var>, <emu-const>frozen</emu-const>).</li><li>Append the Record { [[Site]]: <var>templateLiteral</var>, [[Array]]: <var>template</var> } to <var>realm</var>.[[TemplateMap]].</li><li>Return <var>template</var>.</li></ol></emu-alg>\n        <emu-note>\n          <p>The creation of a template object cannot result in an abrupt completion.</p>\n        </emu-note>\n        <emu-note>\n          <p>Each <emu-nt>TemplateLiteral</emu-nt> in the program code of a realm is associated with a unique template object that is used in the evaluation of tagged Templates (<a href=\"/ecmascript-language-expressions#sec-template-literals-runtime-semantics-evaluation\">13.2.8.6</a>). The template objects are frozen and the same template object is used each time a specific tagged Template is evaluated. Whether template objects are created lazily upon first evaluation of the <emu-nt>TemplateLiteral</emu-nt> or eagerly prior to first evaluation is an implementation choice that is not observable to ECMAScript code.</p>\n        </emu-note>\n        <emu-note>\n          <p>Future editions of this specification may define additional non-enumerable properties of template objects.</p>\n        </emu-note>\n      ","2.8.5":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">TemplateSpans : TemplateTail</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">TemplateSpans : TemplateMiddleList TemplateTail</pre>\n        <emu-alg><ol><li>Return ? SubstitutionEvaluation of <emu-nt>TemplateMiddleList</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">TemplateMiddleList : TemplateMiddle Expression</pre>\n        <emu-alg><ol><li>Let <var>subRef</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Let <var>sub</var> be ? GetValue(<var>subRef</var>).</li><li>Return « <var>sub</var> ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">TemplateMiddleList : TemplateMiddleList TemplateMiddle Expression</pre>\n        <emu-alg><ol><li>Let <var>preceding</var> be ? SubstitutionEvaluation of <emu-nt>TemplateMiddleList</emu-nt>.</li><li>Let <var>nextRef</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Let <var>next</var> be ? GetValue(<var>nextRef</var>).</li><li>Return the list-concatenation of <var>preceding</var> and « <var>next</var> ».</li></ol></emu-alg>\n      ","2.8.6":"<pre class=\"emu-grammar\">TemplateLiteral : NoSubstitutionTemplate</pre>\n        <emu-alg><ol><li>Return the TV of <emu-nt>NoSubstitutionTemplate</emu-nt> as defined in <a href=\"/ecmascript-language-lexical-grammar#sec-template-literal-lexical-components\">12.9.6</a>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">SubstitutionTemplate : TemplateHead Expression TemplateSpans</pre>\n        <emu-alg><ol><li>Let <var>head</var> be the TV of <emu-nt>TemplateHead</emu-nt> as defined in <a href=\"/ecmascript-language-lexical-grammar#sec-template-literal-lexical-components\">12.9.6</a>.</li><li>Let <var>subRef</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Let <var>sub</var> be ? GetValue(<var>subRef</var>).</li><li>Let <var>middle</var> be ? ToString(<var>sub</var>).</li><li>Let <var>tail</var> be ? Evaluation of <emu-nt>TemplateSpans</emu-nt>.</li><li>Return the string-concatenation of <var>head</var>, <var>middle</var>, and <var>tail</var>.</li></ol></emu-alg>\n        <emu-note>\n          <p>The string conversion semantics applied to the <emu-nt>Expression</emu-nt> value are like <code>String.prototype.concat</code> rather than the <code>+</code> operator.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\">TemplateSpans : TemplateTail</pre>\n        <emu-alg><ol><li>Return the TV of <emu-nt>TemplateTail</emu-nt> as defined in <a href=\"/ecmascript-language-lexical-grammar#sec-template-literal-lexical-components\">12.9.6</a>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">TemplateSpans : TemplateMiddleList TemplateTail</pre>\n        <emu-alg><ol><li>Let <var>head</var> be ? Evaluation of <emu-nt>TemplateMiddleList</emu-nt>.</li><li>Let <var>tail</var> be the TV of <emu-nt>TemplateTail</emu-nt> as defined in <a href=\"/ecmascript-language-lexical-grammar#sec-template-literal-lexical-components\">12.9.6</a>.</li><li>Return the string-concatenation of <var>head</var> and <var>tail</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">TemplateMiddleList : TemplateMiddle Expression</pre>\n        <emu-alg><ol><li>Let <var>head</var> be the TV of <emu-nt>TemplateMiddle</emu-nt> as defined in <a href=\"/ecmascript-language-lexical-grammar#sec-template-literal-lexical-components\">12.9.6</a>.</li><li>Let <var>subRef</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Let <var>sub</var> be ? GetValue(<var>subRef</var>).</li><li>Let <var>middle</var> be ? ToString(<var>sub</var>).</li><li>Return the string-concatenation of <var>head</var> and <var>middle</var>.</li></ol></emu-alg>\n        <emu-note>\n          <p>The string conversion semantics applied to the <emu-nt>Expression</emu-nt> value are like <code>String.prototype.concat</code> rather than the <code>+</code> operator.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\">TemplateMiddleList : TemplateMiddleList TemplateMiddle Expression</pre>\n        <emu-alg><ol><li>Let <var>rest</var> be ? Evaluation of <emu-nt>TemplateMiddleList</emu-nt>.</li><li>Let <var>middle</var> be the TV of <emu-nt>TemplateMiddle</emu-nt> as defined in <a href=\"/ecmascript-language-lexical-grammar#sec-template-literal-lexical-components\">12.9.6</a>.</li><li>Let <var>subRef</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Let <var>sub</var> be ? GetValue(<var>subRef</var>).</li><li>Let <var>last</var> be ? ToString(<var>sub</var>).</li><li>Return the string-concatenation of <var>rest</var>, <var>middle</var>, and <var>last</var>.</li></ol></emu-alg>\n        <emu-note>\n          <p>The string conversion semantics applied to the <emu-nt>Expression</emu-nt> value are like <code>String.prototype.concat</code> rather than the <code>+</code> operator.</p>\n        </emu-note>\n      ","2.9":"","2.9.1":"<pre class=\"emu-grammar\">PrimaryExpression : CoverParenthesizedExpressionAndArrowParameterList</pre>\n        <ul>\n          <li>\n            <emu-nt>CoverParenthesizedExpressionAndArrowParameterList</emu-nt> must cover a <emu-nt>ParenthesizedExpression</emu-nt>.\n          </li>\n        </ul>\n      ","2.9.2":"<pre class=\"emu-grammar\">PrimaryExpression : CoverParenthesizedExpressionAndArrowParameterList</pre>\n        <emu-alg><ol><li>Let <var>expr</var> be the <emu-nt>ParenthesizedExpression</emu-nt> that is covered by <emu-nt>CoverParenthesizedExpressionAndArrowParameterList</emu-nt>.</li><li>Return ? Evaluation of <var>expr</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ParenthesizedExpression : `(` Expression `)`</pre>\n        <emu-alg><ol><li>Return ? Evaluation of <emu-nt>Expression</emu-nt>. This may be of type Reference.</li></ol></emu-alg>\n        <emu-note>\n          <p>This algorithm does not apply GetValue to Evaluation of <emu-nt>Expression</emu-nt>. The principal motivation for this is so that operators such as <code>delete</code> and <code>typeof</code> may be applied to parenthesized expressions.</p>\n        </emu-note>\n      ","3.1":"","3.1.1":"<pre class=\"emu-grammar\">OptionalChain :\n  `?.` TemplateLiteral\n  OptionalChain TemplateLiteral</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if any source text is matched by this production.\n          </li>\n        </ul>\n        <emu-note>\n          <p>This production exists in order to prevent automatic semicolon insertion rules (<a href=\"/ecmascript-language-lexical-grammar#sec-automatic-semicolon-insertion\">12.10</a>) from being applied to the following code:</p>\n          <pre><code class=\"javascript\">\n            a?.b\n            `c`\n          </code></pre>\n          <p>so that it would be interpreted as two valid statements. The purpose is to maintain consistency with similar code without optional chaining:</p>\n          <pre><code class=\"javascript\">\n            a.b\n            `c`\n          </code></pre>\n          <p>which is a valid statement and where automatic semicolon insertion does not apply.</p>\n        </emu-note>\n\n        <pre class=\"emu-grammar\">ImportMeta :\n  `import` `.` `meta`</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if the syntactic goal symbol is not <emu-nt>Module</emu-nt>.\n          </li>\n        </ul>\n      ","3.2":"<emu-note>\n        <p>Properties are accessed by name, using either the dot notation:</p>\n        <div class=\"rhs\">\n          <emu-nt>MemberExpression</emu-nt> <code>.</code> <emu-nt>IdentifierName</emu-nt><br>\n          <emu-nt>CallExpression</emu-nt> <code>.</code> <emu-nt>IdentifierName</emu-nt>\n        </div>\n        <p>or the bracket notation:</p>\n        <div class=\"rhs\">\n          <emu-nt>MemberExpression</emu-nt> <code>[</code> <emu-nt>Expression</emu-nt> <code>]</code><br>\n          <emu-nt>CallExpression</emu-nt> <code>[</code> <emu-nt>Expression</emu-nt> <code>]</code>\n        </div>\n        <p>The dot notation is explained by the following syntactic conversion:</p>\n        <div class=\"rhs\">\n          <emu-nt>MemberExpression</emu-nt> <code>.</code> <emu-nt>IdentifierName</emu-nt>\n        </div>\n        <p>is identical in its behaviour to</p>\n        <div class=\"rhs\">\n          <emu-nt>MemberExpression</emu-nt> <code>[</code> &lt;<i>identifier-name-string</i>> <code>]</code>\n        </div>\n        <p>and similarly</p>\n        <div class=\"rhs\">\n          <emu-nt>CallExpression</emu-nt> <code>.</code> <emu-nt>IdentifierName</emu-nt>\n        </div>\n        <p>is identical in its behaviour to</p>\n        <div class=\"rhs\">\n          <emu-nt>CallExpression</emu-nt> <code>[</code> &lt;<i>identifier-name-string</i>> <code>]</code>\n        </div>\n        <p>where &lt;<i>identifier-name-string</i>> is the StringValue of <emu-nt>IdentifierName</emu-nt>.</p>\n      </emu-note>\n\n      ","3.2.1":"<pre class=\"emu-grammar\">MemberExpression : MemberExpression `[` Expression `]`</pre>\n        <emu-alg><ol><li>Let <var>baseReference</var> be ? Evaluation of <emu-nt>MemberExpression</emu-nt>.</li><li>Let <var>baseValue</var> be ? GetValue(<var>baseReference</var>).</li><li>Let <var>strict</var> be IsStrict(this <emu-nt>MemberExpression</emu-nt>).</li><li>Return ? EvaluatePropertyAccessWithExpressionKey(<var>baseValue</var>, <emu-nt>Expression</emu-nt>, <var>strict</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">MemberExpression : MemberExpression `.` IdentifierName</pre>\n        <emu-alg><ol><li>Let <var>baseReference</var> be ? Evaluation of <emu-nt>MemberExpression</emu-nt>.</li><li>Let <var>baseValue</var> be ? GetValue(<var>baseReference</var>).</li><li>Let <var>strict</var> be IsStrict(this <emu-nt>MemberExpression</emu-nt>).</li><li>Return EvaluatePropertyAccessWithIdentifierKey(<var>baseValue</var>, <emu-nt>IdentifierName</emu-nt>, <var>strict</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">MemberExpression : MemberExpression `.` PrivateIdentifier</pre>\n        <emu-alg><ol><li>Let <var>baseReference</var> be ? Evaluation of <emu-nt>MemberExpression</emu-nt>.</li><li>Let <var>baseValue</var> be ? GetValue(<var>baseReference</var>).</li><li>Let <var>fieldNameString</var> be the StringValue of <emu-nt>PrivateIdentifier</emu-nt>.</li><li>Return MakePrivateReference(<var>baseValue</var>, <var>fieldNameString</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">CallExpression : CallExpression `[` Expression `]`</pre>\n        <emu-alg><ol><li>Let <var>baseReference</var> be ? Evaluation of <emu-nt>CallExpression</emu-nt>.</li><li>Let <var>baseValue</var> be ? GetValue(<var>baseReference</var>).</li><li>Let <var>strict</var> be IsStrict(this <emu-nt>CallExpression</emu-nt>).</li><li>Return ? EvaluatePropertyAccessWithExpressionKey(<var>baseValue</var>, <emu-nt>Expression</emu-nt>, <var>strict</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">CallExpression : CallExpression `.` IdentifierName</pre>\n        <emu-alg><ol><li>Let <var>baseReference</var> be ? Evaluation of <emu-nt>CallExpression</emu-nt>.</li><li>Let <var>baseValue</var> be ? GetValue(<var>baseReference</var>).</li><li>Let <var>strict</var> be IsStrict(this <emu-nt>CallExpression</emu-nt>).</li><li>Return EvaluatePropertyAccessWithIdentifierKey(<var>baseValue</var>, <emu-nt>IdentifierName</emu-nt>, <var>strict</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">CallExpression : CallExpression `.` PrivateIdentifier</pre>\n        <emu-alg><ol><li>Let <var>baseReference</var> be ? Evaluation of <emu-nt>CallExpression</emu-nt>.</li><li>Let <var>baseValue</var> be ? GetValue(<var>baseReference</var>).</li><li>Let <var>fieldNameString</var> be the StringValue of <emu-nt>PrivateIdentifier</emu-nt>.</li><li>Return MakePrivateReference(<var>baseValue</var>, <var>fieldNameString</var>).</li></ol></emu-alg>\n      ","3.3":"<dl class=\"header\">\n      </dl>\n      <emu-alg><ol><li>Let <var>propertyNameReference</var> be ? Evaluation of <var>expression</var>.</li><li>Let <var>propertyNameValue</var> be ? GetValue(<var>propertyNameReference</var>).</li><li>NOTE: In most cases, ToPropertyKey will be performed on <var>propertyNameValue</var> immediately after this step. However, in the case of <code>a[b] = c</code>, it will not be performed until after evaluation of <code>c</code>.</li><li>Return the Reference Record { [[Base]]: <var>baseValue</var>, [[ReferencedName]]: <var>propertyNameValue</var>, [[Strict]]: <var>strict</var>, [[ThisValue]]: <emu-const>empty</emu-const> }.</li></ol></emu-alg>\n    ","3.4":"<dl class=\"header\">\n      </dl>\n      <emu-alg><ol><li>Let <var>propertyNameString</var> be the StringValue of <var>identifierName</var>.</li><li>Return the Reference Record { [[Base]]: <var>baseValue</var>, [[ReferencedName]]: <var>propertyNameString</var>, [[Strict]]: <var>strict</var>, [[ThisValue]]: <emu-const>empty</emu-const> }.</li></ol></emu-alg>\n    ","3.5":"","3.5.1":"<pre class=\"emu-grammar\">NewExpression : `new` NewExpression</pre>\n        <emu-alg><ol><li>Return ? EvaluateNew(<emu-nt>NewExpression</emu-nt>, <emu-const>empty</emu-const>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">MemberExpression : `new` MemberExpression Arguments</pre>\n        <emu-alg><ol><li>Return ? EvaluateNew(<emu-nt>MemberExpression</emu-nt>, <emu-nt>Arguments</emu-nt>).</li></ol></emu-alg>\n\n        ","3.5.1.1":"<dl class=\"header\">\n          </dl>\n          <emu-alg><ol><li>Let <var>ref</var> be ? Evaluation of <var>constructExpr</var>.</li><li>Let <var>constructor</var> be ? GetValue(<var>ref</var>).</li><li>If <var>arguments</var> is <emu-const>empty</emu-const>, then<ol><li>Let <var>argList</var> be a new empty List.</li></ol></li><li>Else,<ol><li>Let <var>argList</var> be ? ArgumentListEvaluation of <var>arguments</var>.</li></ol></li><li>If IsConstructor(<var>constructor</var>) is <b>false</b>, throw a <b>TypeError</b> exception.</li><li>Return ? Construct(<var>constructor</var>, <var>argList</var>).</li></ol></emu-alg>\n        ","3.6":"","3.6.1":"<pre class=\"emu-grammar\">CallExpression : CoverCallExpressionAndAsyncArrowHead</pre>\n        <emu-alg><ol><li>Let <var>expr</var> be the <emu-nt>CallMemberExpression</emu-nt> that is covered by <emu-nt>CoverCallExpressionAndAsyncArrowHead</emu-nt>.</li><li>Let <var>memberExpr</var> be the <emu-nt>MemberExpression</emu-nt> of <var>expr</var>.</li><li>Let <var>arguments</var> be the <emu-nt>Arguments</emu-nt> of <var>expr</var>.</li><li>Let <var>ref</var> be ? Evaluation of <var>memberExpr</var>.</li><li>Let <var>func</var> be ? GetValue(<var>ref</var>).</li><li>If <var>ref</var> is a Reference Record, IsPropertyReference(<var>ref</var>) is <b>false</b>, and <var>ref</var>.[[ReferencedName]] is <b>\"eval\"</b>, then<ol><li>If SameValue(<var>func</var>, <code class=\"emu-intrinsic\">%eval%</code>) is <b>true</b>, then<ol><li>Let <var>argList</var> be ? ArgumentListEvaluation of <var>arguments</var>.</li><li>If <var>argList</var> has no elements, return <b>undefined</b>.</li><li>Let <var>evalArg</var> be the first element of <var>argList</var>.</li><li>If IsStrict(this <emu-nt>CallExpression</emu-nt>) is <b>true</b>, let <var>strictCaller</var> be <b>true</b>; else let <var>strictCaller</var> be <b>false</b>.</li><li>Return ? PerformEval(<var>evalArg</var>, <var>strictCaller</var>, <b>true</b>).</li></ol></li></ol></li><li>Let <var>thisCall</var> be this <emu-nt>CallExpression</emu-nt>.</li><li>Let <var>tailCall</var> be IsInTailPosition(<var>thisCall</var>).</li><li>Return ? EvaluateCall(<var>func</var>, <var>ref</var>, <var>arguments</var>, <var>tailCall</var>).</li></ol></emu-alg>\n        <p>A <emu-nt>CallExpression</emu-nt> evaluation that executes step step-callexpression-evaluation-direct-eval is a <dfn variants=\"direct evals\">direct eval</dfn>.</p>\n        <pre class=\"emu-grammar\">CallExpression : CallExpression Arguments</pre>\n        <emu-alg><ol><li>Let <var>ref</var> be ? Evaluation of <emu-nt>CallExpression</emu-nt>.</li><li>Let <var>func</var> be ? GetValue(<var>ref</var>).</li><li>Let <var>thisCall</var> be this <emu-nt>CallExpression</emu-nt>.</li><li>Let <var>tailCall</var> be IsInTailPosition(<var>thisCall</var>).</li><li>Return ? EvaluateCall(<var>func</var>, <var>ref</var>, <emu-nt>Arguments</emu-nt>, <var>tailCall</var>).</li></ol></emu-alg>\n      ","3.6.2":"<dl class=\"header\">\n        </dl>\n        <emu-alg><ol><li>If <var>ref</var> is a Reference Record, then<ol><li>If IsPropertyReference(<var>ref</var>) is <b>true</b>, then<ol><li>Let <var>thisValue</var> be GetThisValue(<var>ref</var>).</li></ol></li><li>Else,<ol><li>Let <var>refEnv</var> be <var>ref</var>.[[Base]].</li><li>Assert: <var>refEnv</var> is an Environment Record.</li><li>Let <var>thisValue</var> be <var>refEnv</var>.WithBaseObject().</li></ol></li></ol></li><li>Else,<ol><li>Let <var>thisValue</var> be <b>undefined</b>.</li></ol></li><li>Let <var>argList</var> be ? ArgumentListEvaluation of <var>arguments</var>.</li><li>If <var>func</var> is not an Object, throw a <b>TypeError</b> exception.</li><li>If IsCallable(<var>func</var>) is <b>false</b>, throw a <b>TypeError</b> exception.</li><li>If <var>tailPosition</var> is <b>true</b>, perform PrepareForTailCall().</li><li>Return ? Call(<var>func</var>, <var>thisValue</var>, <var>argList</var>).</li></ol></emu-alg>\n      ","3.7":"","3.7.1":"<pre class=\"emu-grammar\">SuperProperty : `super` `[` Expression `]`</pre>\n        <emu-alg><ol><li>Let <var>env</var> be GetThisEnvironment().</li><li>Let <var>actualThis</var> be ? <var>env</var>.GetThisBinding().</li><li>Let <var>propertyNameReference</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Let <var>propertyNameValue</var> be ? GetValue(<var>propertyNameReference</var>).</li><li>Let <var>strict</var> be IsStrict(this <emu-nt>SuperProperty</emu-nt>).</li><li>NOTE: In most cases, ToPropertyKey will be performed on <var>propertyNameValue</var> immediately after this step. However, in the case of <code>super[b] = c</code>, it will not be performed until after evaluation of <code>c</code>.</li><li>Return MakeSuperPropertyReference(<var>actualThis</var>, <var>propertyNameValue</var>, <var>strict</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">SuperProperty : `super` `.` IdentifierName</pre>\n        <emu-alg><ol><li>Let <var>env</var> be GetThisEnvironment().</li><li>Let <var>actualThis</var> be ? <var>env</var>.GetThisBinding().</li><li>Let <var>propertyKey</var> be the StringValue of <emu-nt>IdentifierName</emu-nt>.</li><li>Let <var>strict</var> be IsStrict(this <emu-nt>SuperProperty</emu-nt>).</li><li>Return MakeSuperPropertyReference(<var>actualThis</var>, <var>propertyKey</var>, <var>strict</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">SuperCall : `super` Arguments</pre>\n        <emu-alg><ol><li>Let <var>newTarget</var> be GetNewTarget().</li><li>Assert: <var>newTarget</var> is a constructor.</li><li>Let <var>superConstructor</var> be GetSuperConstructor().</li><li>Let <var>argList</var> be ? ArgumentListEvaluation of <emu-nt>Arguments</emu-nt>.</li><li>If IsConstructor(<var>superConstructor</var>) is <b>false</b>, throw a <b>TypeError</b> exception.</li><li>Let <var>result</var> be ? Construct(<var>superConstructor</var>, <var>argList</var>, <var>newTarget</var>).</li><li>Let <var>thisER</var> be GetThisEnvironment().</li><li>Assert: <var>thisER</var> is a Function Environment Record.</li><li>Perform ? BindThisValue(<var>thisER</var>, <var>result</var>).</li><li>Let <var>funcObj</var> be <var>thisER</var>.[[FunctionObject]].</li><li>Assert: <var>funcObj</var> is an ECMAScript function object.</li><li>Perform ? InitializeInstanceElements(<var>result</var>, <var>funcObj</var>).</li><li>Return <var>result</var>.</li></ol></emu-alg>\n      ","3.7.2":"<dl class=\"header\">\n        </dl>\n        <emu-alg><ol><li>Let <var>envRec</var> be GetThisEnvironment().</li><li>Assert: <var>envRec</var> is a Function Environment Record.</li><li>Let <var>activeFunction</var> be <var>envRec</var>.[[FunctionObject]].</li><li>Assert: <var>activeFunction</var> is an ECMAScript function object.</li><li>Let <var>superConstructor</var> be ! <var>activeFunction</var>.[[GetPrototypeOf]]().</li><li>Return <var>superConstructor</var>.</li></ol></emu-alg>\n      ","3.7.3":"<dl class=\"header\">\n        </dl>\n        <emu-alg><ol><li>Let <var>env</var> be GetThisEnvironment().</li><li>Assert: <var>env</var>.HasSuperBinding() is <b>true</b>.</li><li>Assert: <var>env</var> is a Function Environment Record.</li><li>Let <var>baseValue</var> be GetSuperBase(<var>env</var>).</li><li>Return the Reference Record { [[Base]]: <var>baseValue</var>, [[ReferencedName]]: <var>propertyKey</var>, [[Strict]]: <var>strict</var>, [[ThisValue]]: <var>actualThis</var> }.</li></ol></emu-alg>\n      ","3.8":"<emu-note>\n        <p>The evaluation of an argument list produces a List of values.</p>\n      </emu-note>\n\n      ","3.8.1":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">Arguments : `(` `)`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ArgumentList : AssignmentExpression</pre>\n        <emu-alg><ol><li>Let <var>ref</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>arg</var> be ? GetValue(<var>ref</var>).</li><li>Return « <var>arg</var> ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ArgumentList : `...` AssignmentExpression</pre>\n        <emu-alg><ol><li>Let <var>list</var> be a new empty List.</li><li>Let <var>spreadRef</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>spreadObj</var> be ? GetValue(<var>spreadRef</var>).</li><li>Let <var>iteratorRecord</var> be ? GetIterator(<var>spreadObj</var>, <emu-const>sync</emu-const>).</li><li>Repeat,<ol><li>Let <var>next</var> be ? IteratorStepValue(<var>iteratorRecord</var>).</li><li>If <var>next</var> is <emu-const>done</emu-const>, return <var>list</var>.</li><li>Append <var>next</var> to <var>list</var>.</li></ol></li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ArgumentList : ArgumentList `,` AssignmentExpression</pre>\n        <emu-alg><ol><li>Let <var>precedingArgs</var> be ? ArgumentListEvaluation of <emu-nt>ArgumentList</emu-nt>.</li><li>Let <var>ref</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>arg</var> be ? GetValue(<var>ref</var>).</li><li>Return the list-concatenation of <var>precedingArgs</var> and « <var>arg</var> ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ArgumentList : ArgumentList `,` `...` AssignmentExpression</pre>\n        <emu-alg><ol><li>Let <var>precedingArgs</var> be ? ArgumentListEvaluation of <emu-nt>ArgumentList</emu-nt>.</li><li>Let <var>spreadRef</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>iteratorRecord</var> be ? GetIterator(? GetValue(<var>spreadRef</var>), <emu-const>sync</emu-const>).</li><li>Repeat,<ol><li>Let <var>next</var> be ? IteratorStepValue(<var>iteratorRecord</var>).</li><li>If <var>next</var> is <emu-const>done</emu-const>, return <var>precedingArgs</var>.</li><li>Append <var>next</var> to <var>precedingArgs</var>.</li></ol></li></ol></emu-alg>\n        <pre class=\"emu-grammar\">TemplateLiteral : NoSubstitutionTemplate</pre>\n        <emu-alg><ol><li>Let <var>templateLiteral</var> be this <emu-nt>TemplateLiteral</emu-nt>.</li><li>Let <var>siteObj</var> be GetTemplateObject(<var>templateLiteral</var>).</li><li>Return « <var>siteObj</var> ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">TemplateLiteral : SubstitutionTemplate</pre>\n        <emu-alg><ol><li>Let <var>templateLiteral</var> be this <emu-nt>TemplateLiteral</emu-nt>.</li><li>Let <var>siteObj</var> be GetTemplateObject(<var>templateLiteral</var>).</li><li>Let <var>remaining</var> be ? ArgumentListEvaluation of <emu-nt>SubstitutionTemplate</emu-nt>.</li><li>Return the list-concatenation of « <var>siteObj</var> » and <var>remaining</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">SubstitutionTemplate : TemplateHead Expression TemplateSpans</pre>\n        <emu-alg><ol><li>Let <var>firstSubRef</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Let <var>firstSub</var> be ? GetValue(<var>firstSubRef</var>).</li><li>Let <var>restSub</var> be ? SubstitutionEvaluation of <emu-nt>TemplateSpans</emu-nt>.</li><li>Assert: <var>restSub</var> is a possibly empty List.</li><li>Return the list-concatenation of « <var>firstSub</var> » and <var>restSub</var>.</li></ol></emu-alg>\n      ","3.9":"<emu-note>An optional chain is a chain of one or more property accesses and function calls, the first of which begins with the token <code>?.</code>.</emu-note>\n\n      ","3.9.1":"<pre class=\"emu-grammar\">OptionalExpression :\n  MemberExpression OptionalChain</pre>\n        <emu-alg><ol><li>Let <var>baseReference</var> be ? Evaluation of <emu-nt>MemberExpression</emu-nt>.</li><li>Let <var>baseValue</var> be ? GetValue(<var>baseReference</var>).</li><li>If <var>baseValue</var> is either <b>undefined</b> or <b>null</b>, then<ol><li>Return <b>undefined</b>.</li></ol></li><li>Return ? ChainEvaluation of <emu-nt>OptionalChain</emu-nt> with arguments <var>baseValue</var> and <var>baseReference</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">OptionalExpression :\n  CallExpression OptionalChain</pre>\n        <emu-alg><ol><li>Let <var>baseReference</var> be ? Evaluation of <emu-nt>CallExpression</emu-nt>.</li><li>Let <var>baseValue</var> be ? GetValue(<var>baseReference</var>).</li><li>If <var>baseValue</var> is either <b>undefined</b> or <b>null</b>, then<ol><li>Return <b>undefined</b>.</li></ol></li><li>Return ? ChainEvaluation of <emu-nt>OptionalChain</emu-nt> with arguments <var>baseValue</var> and <var>baseReference</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">OptionalExpression :\n  OptionalExpression OptionalChain</pre>\n        <emu-alg><ol><li>Let <var>baseReference</var> be ? Evaluation of <emu-nt>OptionalExpression</emu-nt>.</li><li>Let <var>baseValue</var> be ? GetValue(<var>baseReference</var>).</li><li>If <var>baseValue</var> is either <b>undefined</b> or <b>null</b>, then<ol><li>Return <b>undefined</b>.</li></ol></li><li>Return ? ChainEvaluation of <emu-nt>OptionalChain</emu-nt> with arguments <var>baseValue</var> and <var>baseReference</var>.</li></ol></emu-alg>\n      ","3.9.2":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">OptionalChain : `?.` Arguments</pre>\n        <emu-alg><ol><li>Let <var>thisChain</var> be this <emu-nt>OptionalChain</emu-nt>.</li><li>Let <var>tailCall</var> be IsInTailPosition(<var>thisChain</var>).</li><li>Return ? EvaluateCall(<var>baseValue</var>, <var>baseReference</var>, <emu-nt>Arguments</emu-nt>, <var>tailCall</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">OptionalChain : `?.` `[` Expression `]`</pre>\n        <emu-alg><ol><li>Let <var>strict</var> be IsStrict(this <emu-nt>OptionalChain</emu-nt>).</li><li>Return ? EvaluatePropertyAccessWithExpressionKey(<var>baseValue</var>, <emu-nt>Expression</emu-nt>, <var>strict</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">OptionalChain : `?.` IdentifierName</pre>\n        <emu-alg><ol><li>Let <var>strict</var> be IsStrict(this <emu-nt>OptionalChain</emu-nt>).</li><li>Return EvaluatePropertyAccessWithIdentifierKey(<var>baseValue</var>, <emu-nt>IdentifierName</emu-nt>, <var>strict</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">OptionalChain : `?.` PrivateIdentifier</pre>\n        <emu-alg><ol><li>Let <var>fieldNameString</var> be the StringValue of <emu-nt>PrivateIdentifier</emu-nt>.</li><li>Return MakePrivateReference(<var>baseValue</var>, <var>fieldNameString</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">OptionalChain : OptionalChain Arguments</pre>\n        <emu-alg><ol><li>Let <var>optionalChain</var> be <emu-nt>OptionalChain</emu-nt>.</li><li>Let <var>newReference</var> be ? ChainEvaluation of <var>optionalChain</var> with arguments <var>baseValue</var> and <var>baseReference</var>.</li><li>Let <var>newValue</var> be ? GetValue(<var>newReference</var>).</li><li>Let <var>thisChain</var> be this <emu-nt>OptionalChain</emu-nt>.</li><li>Let <var>tailCall</var> be IsInTailPosition(<var>thisChain</var>).</li><li>Return ? EvaluateCall(<var>newValue</var>, <var>newReference</var>, <emu-nt>Arguments</emu-nt>, <var>tailCall</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">OptionalChain : OptionalChain `[` Expression `]`</pre>\n        <emu-alg><ol><li>Let <var>optionalChain</var> be <emu-nt>OptionalChain</emu-nt>.</li><li>Let <var>newReference</var> be ? ChainEvaluation of <var>optionalChain</var> with arguments <var>baseValue</var> and <var>baseReference</var>.</li><li>Let <var>newValue</var> be ? GetValue(<var>newReference</var>).</li><li>Let <var>strict</var> be IsStrict(this <emu-nt>OptionalChain</emu-nt>).</li><li>Return ? EvaluatePropertyAccessWithExpressionKey(<var>newValue</var>, <emu-nt>Expression</emu-nt>, <var>strict</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">OptionalChain : OptionalChain `.` IdentifierName</pre>\n        <emu-alg><ol><li>Let <var>optionalChain</var> be <emu-nt>OptionalChain</emu-nt>.</li><li>Let <var>newReference</var> be ? ChainEvaluation of <var>optionalChain</var> with arguments <var>baseValue</var> and <var>baseReference</var>.</li><li>Let <var>newValue</var> be ? GetValue(<var>newReference</var>).</li><li>Let <var>strict</var> be IsStrict(this <emu-nt>OptionalChain</emu-nt>).</li><li>Return EvaluatePropertyAccessWithIdentifierKey(<var>newValue</var>, <emu-nt>IdentifierName</emu-nt>, <var>strict</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">OptionalChain : OptionalChain `.` PrivateIdentifier</pre>\n        <emu-alg><ol><li>Let <var>optionalChain</var> be <emu-nt>OptionalChain</emu-nt>.</li><li>Let <var>newReference</var> be ? ChainEvaluation of <var>optionalChain</var> with arguments <var>baseValue</var> and <var>baseReference</var>.</li><li>Let <var>newValue</var> be ? GetValue(<var>newReference</var>).</li><li>Let <var>fieldNameString</var> be the StringValue of <emu-nt>PrivateIdentifier</emu-nt>.</li><li>Return MakePrivateReference(<var>newValue</var>, <var>fieldNameString</var>).</li></ol></emu-alg>\n      ","3.10":"","3.10.1":"<pre class=\"emu-grammar\">ImportCall : `import` `(` AssignmentExpression `,`? `)`</pre>\n        <emu-alg><ol><li>Return ? EvaluateImportCall(<emu-nt>AssignmentExpression</emu-nt>).</li></ol></emu-alg>\n\n        <pre class=\"emu-grammar\">ImportCall : `import` `(` AssignmentExpression `,` AssignmentExpression `,`? `)`</pre>\n        <emu-alg><ol><li>Return ? EvaluateImportCall(the first <emu-nt>AssignmentExpression</emu-nt>, the second <emu-nt>AssignmentExpression</emu-nt>).</li></ol></emu-alg>\n      ","3.10.2":"<dl class=\"header\">\n        </dl>\n        <emu-alg><ol><li>Let <var>referrer</var> be GetActiveScriptOrModule().</li><li>If <var>referrer</var> is <b>null</b>, set <var>referrer</var> to the current Realm Record.</li><li>Let <var>specifierRef</var> be ? Evaluation of <var>specifierExpression</var>.</li><li>Let <var>specifier</var> be ? GetValue(<var>specifierRef</var>).</li><li>If <var>optionsExpression</var> is present, then<ol><li>Let <var>optionsRef</var> be ? Evaluation of <var>optionsExpression</var>.</li><li>Let <var>options</var> be ? GetValue(<var>optionsRef</var>).</li></ol></li><li>Else,<ol><li>Let <var>options</var> be <b>undefined</b>.</li></ol></li><li>Let <var>promiseCapability</var> be ! NewPromiseCapability(<code class=\"emu-intrinsic\">%Promise%</code>).</li><li>Let <var>specifierString</var> be Completion(ToString(<var>specifier</var>)).</li><li>IfAbruptRejectPromise(<var>specifierString</var>, <var>promiseCapability</var>).</li><li>Let <var>attributes</var> be a new empty List.</li><li>If <var>options</var> is not <b>undefined</b>, then<ol><li>If <var>options</var> is not an Object, then<ol><li>Perform ! Call(<var>promiseCapability</var>.[[Reject]], <b>undefined</b>, « a newly created <b>TypeError</b> object »).</li><li>Return <var>promiseCapability</var>.[[Promise]].</li></ol></li><li>Let <var>attributesObj</var> be Completion(Get(<var>options</var>, <b>\"with\"</b>)).</li><li>IfAbruptRejectPromise(<var>attributesObj</var>, <var>promiseCapability</var>).</li><li>If <var>attributesObj</var> is not <b>undefined</b>, then<ol><li>If <var>attributesObj</var> is not an Object, then<ol><li>Perform ! Call(<var>promiseCapability</var>.[[Reject]], <b>undefined</b>, « a newly created <b>TypeError</b> object »).</li><li>Return <var>promiseCapability</var>.[[Promise]].</li></ol></li><li>Let <var>entries</var> be Completion(EnumerableOwnProperties(<var>attributesObj</var>, <emu-const>key+value</emu-const>)).</li><li>IfAbruptRejectPromise(<var>entries</var>, <var>promiseCapability</var>).</li><li>For each element <var>entry</var> of <var>entries</var>, do<ol><li>Let <var>key</var> be ! Get(<var>entry</var>, <b>\"0\"</b>).</li><li>Let <var>value</var> be ! Get(<var>entry</var>, <b>\"1\"</b>).</li><li>If <var>key</var> is a String, then<ol><li>If <var>value</var> is not a String, then<ol><li>Perform ! Call(<var>promiseCapability</var>.[[Reject]], <b>undefined</b>, « a newly created <b>TypeError</b> object »).</li><li>Return <var>promiseCapability</var>.[[Promise]].</li></ol></li><li>Append the ImportAttribute Record { [[Key]]: <var>key</var>, [[Value]]: <var>value</var> } to <var>attributes</var>.</li></ol></li></ol></li></ol></li><li>If AllImportAttributesSupported(<var>attributes</var>) is <b>false</b>, then<ol><li>Perform ! Call(<var>promiseCapability</var>.[[Reject]], <b>undefined</b>, « a newly created <b>TypeError</b> object »).</li><li>Return <var>promiseCapability</var>.[[Promise]].</li></ol></li><li>Sort <var>attributes</var> according to the lexicographic order of their [[Key]] field, treating the value of each such field as a sequence of UTF-16 code unit values. NOTE: This sorting is observable only in that hosts are prohibited from changing behaviour based on the order in which attributes are enumerated.</li></ol></li><li>Let <var>moduleRequest</var> be a new ModuleRequest Record { [[Specifier]]: <var>specifierString</var>, [[Attributes]]: <var>attributes</var> }.</li><li>Perform HostLoadImportedModule(<var>referrer</var>, <var>moduleRequest</var>, <emu-const>empty</emu-const>, <var>promiseCapability</var>).</li><li>Return <var>promiseCapability</var>.[[Promise]].</li></ol></emu-alg>\n      ","3.10.3":"<dl class=\"header\">\n          <dt>description</dt>\n          <dd>It completes the process of a dynamic import originally started by an <a href=\"/ecmascript-language-expressions#sec-import-calls\"><code>import()</code></a> call, resolving or rejecting the promise returned by that call as appropriate.</dd>\n        </dl>\n        <emu-alg><ol><li>If <var>moduleCompletion</var> is an abrupt completion, then<ol><li>Perform ! Call(<var>promiseCapability</var>.[[Reject]], <b>undefined</b>, « <var>moduleCompletion</var>.[[Value]] »).</li><li>Return <emu-const>unused</emu-const>.</li></ol></li><li>Let <var>module</var> be <var>moduleCompletion</var>.[[Value]].</li><li>Let <var>loadPromise</var> be <var>module</var>.LoadRequestedModules().</li><li>Let <var>rejectedClosure</var> be a new Abstract Closure with parameters (<var>reason</var>) that captures <var>promiseCapability</var> and performs the following steps when called:<ol><li>Perform ! Call(<var>promiseCapability</var>.[[Reject]], <b>undefined</b>, « <var>reason</var> »).</li><li>Return NormalCompletion(<b>undefined</b>).</li></ol></li><li>Let <var>onRejected</var> be CreateBuiltinFunction(<var>rejectedClosure</var>, 1, <b>\"\"</b>, « »).</li><li>Let <var>linkAndEvaluateClosure</var> be a new Abstract Closure with no parameters that captures <var>module</var>, <var>promiseCapability</var>, and <var>onRejected</var> and performs the following steps when called:<ol><li>Let <var>link</var> be Completion(<var>module</var>.Link()).</li><li>If <var>link</var> is an abrupt completion, then<ol><li>Perform ! Call(<var>promiseCapability</var>.[[Reject]], <b>undefined</b>, « <var>link</var>.[[Value]] »).</li><li>Return NormalCompletion(<b>undefined</b>).</li></ol></li><li>Let <var>evaluatePromise</var> be <var>module</var>.Evaluate().</li><li>Let <var>fulfilledClosure</var> be a new Abstract Closure with no parameters that captures <var>module</var> and <var>promiseCapability</var> and performs the following steps when called:<ol><li>Let <var>namespace</var> be GetModuleNamespace(<var>module</var>).</li><li>Perform ! <emu-meta effects=\"user-code\">Call(<var>promiseCapability</var>.[[Resolve]], <b>undefined</b>, « <var>namespace</var> »)</emu-meta>.</li><li>Return NormalCompletion(<b>undefined</b>).</li></ol></li><li>Let <var>onFulfilled</var> be CreateBuiltinFunction(<var>fulfilledClosure</var>, 0, <b>\"\"</b>, « »).</li><li>Perform PerformPromiseThen(<var>evaluatePromise</var>, <var>onFulfilled</var>, <var>onRejected</var>).</li><li>Return <emu-const>unused</emu-const>.</li></ol></li><li>Let <var>linkAndEvaluate</var> be CreateBuiltinFunction(<var>linkAndEvaluateClosure</var>, 0, <b>\"\"</b>, « »).</li><li>Perform PerformPromiseThen(<var>loadPromise</var>, <var>linkAndEvaluate</var>, <var>onRejected</var>).</li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n      ","3.11":"<emu-note>\n        <p>A tagged template is a function call where the arguments of the call are derived from a <emu-nt>TemplateLiteral</emu-nt> (<a href=\"/ecmascript-language-expressions#sec-template-literals\">13.2.8</a>). The actual arguments include a template object (<a href=\"/ecmascript-language-expressions#sec-gettemplateobject\">13.2.8.4</a>) and the values produced by evaluating the expressions embedded within the <emu-nt>TemplateLiteral</emu-nt>.</p>\n      </emu-note>\n\n      ","3.11.1":"<pre class=\"emu-grammar\">MemberExpression : MemberExpression TemplateLiteral</pre>\n        <emu-alg><ol><li>Let <var>tagRef</var> be ? Evaluation of <emu-nt>MemberExpression</emu-nt>.</li><li>Let <var>tagFunc</var> be ? GetValue(<var>tagRef</var>).</li><li>Let <var>thisCall</var> be this <emu-nt>MemberExpression</emu-nt>.</li><li>Let <var>tailCall</var> be IsInTailPosition(<var>thisCall</var>).</li><li>Return ? EvaluateCall(<var>tagFunc</var>, <var>tagRef</var>, <emu-nt>TemplateLiteral</emu-nt>, <var>tailCall</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">CallExpression : CallExpression TemplateLiteral</pre>\n        <emu-alg><ol><li>Let <var>tagRef</var> be ? Evaluation of <emu-nt>CallExpression</emu-nt>.</li><li>Let <var>tagFunc</var> be ? GetValue(<var>tagRef</var>).</li><li>Let <var>thisCall</var> be this <emu-nt>CallExpression</emu-nt>.</li><li>Let <var>tailCall</var> be IsInTailPosition(<var>thisCall</var>).</li><li>Return ? EvaluateCall(<var>tagFunc</var>, <var>tagRef</var>, <emu-nt>TemplateLiteral</emu-nt>, <var>tailCall</var>).</li></ol></emu-alg>\n      ","3.12":"","3.12.1":"<pre class=\"emu-grammar\">NewTarget : `new` `.` `target`</pre>\n        <emu-alg><ol><li>Return GetNewTarget().</li></ol></emu-alg>\n\n        <pre class=\"emu-grammar\">ImportMeta : `import` `.` `meta`</pre>\n        <emu-alg><ol><li>Let <var>module</var> be GetActiveScriptOrModule().</li><li>Assert: <var>module</var> is a Source Text Module Record.</li><li>Let <var>importMeta</var> be <var>module</var>.[[ImportMeta]].</li><li>If <var>importMeta</var> is <emu-const>empty</emu-const>, then<ol><li>Set <var>importMeta</var> to OrdinaryObjectCreate(<b>null</b>).</li><li>Let <var>importMetaValues</var> be HostGetImportMetaProperties(<var>module</var>).</li><li>For each Record { [[Key]], [[Value]] } <var>p</var> of <var>importMetaValues</var>, do<ol><li>Perform ! CreateDataPropertyOrThrow(<var>importMeta</var>, <var>p</var>.[[Key]], <var>p</var>.[[Value]]).</li></ol></li><li>Perform HostFinalizeImportMeta(<var>importMeta</var>, <var>module</var>).</li><li>Set <var>module</var>.[[ImportMeta]] to <var>importMeta</var>.</li><li>Return <var>importMeta</var>.</li></ol></li><li>Assert: <var>importMeta</var> is an Object.</li><li>Return <var>importMeta</var>.</li></ol></emu-alg>\n\n        ","3.12.1.1":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd>It allows hosts to provide property keys and values for the object returned from <code>import.meta</code>.</dd>\n          </dl>\n\n          <p>The default implementation of HostGetImportMetaProperties is to return a new empty List.</p>\n        ","3.12.1.2":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd>It allows hosts to perform any extraordinary operations to prepare the object returned from <code>import.meta</code>.</dd>\n          </dl>\n\n          <p>Most hosts will be able to simply define HostGetImportMetaProperties, and leave HostFinalizeImportMeta with its default behaviour. However, HostFinalizeImportMeta provides an \"escape hatch\" for hosts which need to directly manipulate the object before it is exposed to ECMAScript code.</p>\n\n          <p>The default implementation of HostFinalizeImportMeta is to return <emu-const>unused</emu-const>.</p>\n        ","4.1":"<pre class=\"emu-grammar\">UpdateExpression :\n  LeftHandSideExpression `++`\n  LeftHandSideExpression `--`</pre>\n      <ul>\n        <li>\n          It is an early Syntax Error if the AssignmentTargetType of <emu-nt>LeftHandSideExpression</emu-nt> is <emu-const>invalid</emu-const>.\n        </li>\n      </ul>\n\n      <pre class=\"emu-grammar\">UpdateExpression :\n  `++` UnaryExpression\n  `--` UnaryExpression</pre>\n      <ul>\n        <li>\n          It is an early Syntax Error if the AssignmentTargetType of <emu-nt>UnaryExpression</emu-nt> is <emu-const>invalid</emu-const>.\n        </li>\n      </ul>\n    ","4.2":"","4.2.1":"<pre class=\"emu-grammar\">UpdateExpression : LeftHandSideExpression `++`</pre>\n        <emu-alg><ol><li>Let <var>lhs</var> be ? Evaluation of <emu-nt>LeftHandSideExpression</emu-nt>.</li><li>If the AssignmentTargetType of <emu-nt>LeftHandSideExpression</emu-nt> is <emu-const>web-compat</emu-const>, throw a <b>ReferenceError</b> exception.</li><li>Let <var>oldValue</var> be ? ToNumeric(? GetValue(<var>lhs</var>)).</li><li>If <var>oldValue</var> is a Number, then<ol><li>Let <var>newValue</var> be Number::add(<var>oldValue</var>, <b>1</b><sub>𝔽</sub>).</li></ol></li><li>Else,<ol><li>Assert: <var>oldValue</var> is a BigInt.</li><li>Let <var>newValue</var> be BigInt::add(<var>oldValue</var>, <b>1</b><sub>ℤ</sub>).</li></ol></li><li>Perform ? PutValue(<var>lhs</var>, <var>newValue</var>).</li><li>Return <var>oldValue</var>.</li></ol></emu-alg>\n      ","4.3":"","4.3.1":"<pre class=\"emu-grammar\">UpdateExpression : LeftHandSideExpression `--`</pre>\n        <emu-alg><ol><li>Let <var>lhs</var> be ? Evaluation of <emu-nt>LeftHandSideExpression</emu-nt>.</li><li>If the AssignmentTargetType of <emu-nt>LeftHandSideExpression</emu-nt> is <emu-const>web-compat</emu-const>, throw a <b>ReferenceError</b> exception.</li><li>Let <var>oldValue</var> be ? ToNumeric(? GetValue(<var>lhs</var>)).</li><li>If <var>oldValue</var> is a Number, then<ol><li>Let <var>newValue</var> be Number::subtract(<var>oldValue</var>, <b>1</b><sub>𝔽</sub>).</li></ol></li><li>Else,<ol><li>Assert: <var>oldValue</var> is a BigInt.</li><li>Let <var>newValue</var> be BigInt::subtract(<var>oldValue</var>, <b>1</b><sub>ℤ</sub>).</li></ol></li><li>Perform ? PutValue(<var>lhs</var>, <var>newValue</var>).</li><li>Return <var>oldValue</var>.</li></ol></emu-alg>\n      ","4.4":"","4.4.1":"<pre class=\"emu-grammar\">UpdateExpression : `++` UnaryExpression</pre>\n        <emu-alg><ol><li>Let <var>expr</var> be ? Evaluation of <emu-nt>UnaryExpression</emu-nt>.</li><li>If the AssignmentTargetType of <emu-nt>UnaryExpression</emu-nt> is <emu-const>web-compat</emu-const>, throw a <b>ReferenceError</b> exception.</li><li>Let <var>oldValue</var> be ? ToNumeric(? GetValue(<var>expr</var>)).</li><li>If <var>oldValue</var> is a Number, then<ol><li>Let <var>newValue</var> be Number::add(<var>oldValue</var>, <b>1</b><sub>𝔽</sub>).</li></ol></li><li>Else,<ol><li>Assert: <var>oldValue</var> is a BigInt.</li><li>Let <var>newValue</var> be BigInt::add(<var>oldValue</var>, <b>1</b><sub>ℤ</sub>).</li></ol></li><li>Perform ? PutValue(<var>expr</var>, <var>newValue</var>).</li><li>Return <var>newValue</var>.</li></ol></emu-alg>\n      ","4.5":"","4.5.1":"<pre class=\"emu-grammar\">UpdateExpression : `--` UnaryExpression</pre>\n        <emu-alg><ol><li>Let <var>expr</var> be ? Evaluation of <emu-nt>UnaryExpression</emu-nt>.</li><li>If the AssignmentTargetType of <emu-nt>UnaryExpression</emu-nt> is <emu-const>web-compat</emu-const>, throw a <b>ReferenceError</b> exception.</li><li>Let <var>oldValue</var> be ? ToNumeric(? GetValue(<var>expr</var>)).</li><li>If <var>oldValue</var> is a Number, then<ol><li>Let <var>newValue</var> be Number::subtract(<var>oldValue</var>, <b>1</b><sub>𝔽</sub>).</li></ol></li><li>Else,<ol><li>Assert: <var>oldValue</var> is a BigInt.</li><li>Let <var>newValue</var> be BigInt::subtract(<var>oldValue</var>, <b>1</b><sub>ℤ</sub>).</li></ol></li><li>Perform ? PutValue(<var>expr</var>, <var>newValue</var>).</li><li>Return <var>newValue</var>.</li></ol></emu-alg>\n      ","5.1":"","5.1.1":"<pre class=\"emu-grammar\">UnaryExpression : `delete` UnaryExpression</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if IsStrict(the <emu-nt>UnaryExpression</emu-nt>) is <b>true</b> and the derived <emu-nt>UnaryExpression</emu-nt> is <code class=\"emu-grammar\">PrimaryExpression : IdentifierReference</code>, <code class=\"emu-grammar\">MemberExpression : MemberExpression `.` PrivateIdentifier</code>, <code class=\"emu-grammar\">CallExpression : CallExpression `.` PrivateIdentifier</code>, <code class=\"emu-grammar\">OptionalChain : `?.` PrivateIdentifier</code>, or <code class=\"emu-grammar\">OptionalChain : OptionalChain `.` PrivateIdentifier</code>.\n          </li>\n          <li>\n            <p>\n              It is a Syntax Error if the derived <emu-nt>UnaryExpression</emu-nt> is<br>\n              <pre class=\"emu-grammar\">PrimaryExpression : CoverParenthesizedExpressionAndArrowParameterList</pre><br>\n              and <emu-nt>CoverParenthesizedExpressionAndArrowParameterList</emu-nt> ultimately derives a phrase that, if used in place of <emu-nt>UnaryExpression</emu-nt>, would produce a Syntax Error according to these rules. This rule is recursively applied.\n            </p>\n          </li>\n        </ul>\n        <emu-note>\n          <p>The last rule means that expressions such as <code>delete (((foo)))</code> produce early errors because of recursive application of the first rule.</p>\n        </emu-note>\n      ","5.1.2":"<pre class=\"emu-grammar\">UnaryExpression : `delete` UnaryExpression</pre>\n        <emu-alg><ol><li>Let <var>ref</var> be ? Evaluation of <emu-nt>UnaryExpression</emu-nt>.</li><li>If <var>ref</var> is not a Reference Record, return <b>true</b>.</li><li>If IsUnresolvableReference(<var>ref</var>) is <b>true</b>, then<ol><li>Assert: <var>ref</var>.[[Strict]] is <b>false</b>.</li><li>Return <b>true</b>.</li></ol></li><li>If IsPropertyReference(<var>ref</var>) is <b>true</b>, then<ol><li>Assert: IsPrivateReference(<var>ref</var>) is <b>false</b>.</li><li>If IsSuperReference(<var>ref</var>) is <b>true</b>, throw a <b>ReferenceError</b> exception.</li><li>Let <var>baseObj</var> be ? ToObject(<var>ref</var>.[[Base]]).</li><li>If <var>ref</var>.[[ReferencedName]] is not a property key, then<ol><li>Set <var>ref</var>.[[ReferencedName]] to ? ToPropertyKey(<var>ref</var>.[[ReferencedName]]).</li></ol></li><li>Let <var>deleteStatus</var> be ? <emu-meta effects=\"user-code\"><var>baseObj</var>.[[Delete]](<var>ref</var>.[[ReferencedName]])</emu-meta>.</li><li>If <var>deleteStatus</var> is <b>false</b> and <var>ref</var>.[[Strict]] is <b>true</b>, throw a <b>TypeError</b> exception.</li><li>Return <var>deleteStatus</var>.</li></ol></li><li>Let <var>base</var> be <var>ref</var>.[[Base]].</li><li>Assert: <var>base</var> is an Environment Record.</li><li>Return ? <emu-meta effects=\"user-code\"><var>base</var>.DeleteBinding(<var>ref</var>.[[ReferencedName]])</emu-meta>.</li></ol></emu-alg>\n        <emu-note>\n          <p>When a <code>delete</code> operator occurs within strict mode code, a <b>SyntaxError</b> exception is thrown if its <emu-nt>UnaryExpression</emu-nt> is a direct reference to a variable, function argument, or function name. In addition, if a <code>delete</code> operator occurs within strict mode code and the property to be deleted has the attribute { [[Configurable]]: <b>false</b> } (or otherwise cannot be deleted), a <b>TypeError</b> exception is thrown.</p>\n        </emu-note>\n        <emu-note>\n          <p>The object that may be created in step step-delete-operator-toobject is not accessible outside of the above abstract operation and the ordinary object [[Delete]] internal method. An implementation might choose to avoid the actual creation of that object.</p>\n        </emu-note>\n      ","5.2":"","5.2.1":"<pre class=\"emu-grammar\">UnaryExpression : `void` UnaryExpression</pre>\n        <emu-alg><ol><li>Let <var>expr</var> be ? Evaluation of <emu-nt>UnaryExpression</emu-nt>.</li><li>Perform ? GetValue(<var>expr</var>).</li><li>Return <b>undefined</b>.</li></ol></emu-alg>\n        <emu-note>\n          <p>GetValue must be called even though its value is not used because it may have observable side-effects.</p>\n        </emu-note>\n      ","5.3":"","5.3.1":"<pre class=\"emu-grammar\">UnaryExpression : `typeof` UnaryExpression</pre>\n        <emu-alg><ol><li>Let <var>val</var> be ? Evaluation of <emu-nt>UnaryExpression</emu-nt>.</li><li>If <var>val</var> is a Reference Record, then<ol><li>If IsUnresolvableReference(<var>val</var>) is <b>true</b>, return <b>\"undefined\"</b>.</li></ol></li><li>Set <var>val</var> to ? GetValue(<var>val</var>).</li><li>If <var>val</var> is <b>undefined</b>, return <b>\"undefined\"</b>.</li><li>If <var>val</var> is <b>null</b>, return <b>\"object\"</b>.</li><li>If <var>val</var> is a String, return <b>\"string\"</b>.</li><li>If <var>val</var> is a Symbol, return <b>\"symbol\"</b>.</li><li>If <var>val</var> is a Boolean, return <b>\"boolean\"</b>.</li><li>If <var>val</var> is a Number, return <b>\"number\"</b>.</li><li>If <var>val</var> is a BigInt, return <b>\"bigint\"</b>.</li><li>Assert: <var>val</var> is an Object.</li><li>If the host is a web browser or otherwise supports <a href=\"/additional-ecmascript-features-for-web-browsers#sec-IsHTMLDDA-internal-slot\">B.3.6</a>, then<ol><li>If <var>val</var> has an [[IsHTMLDDA]] internal slot, return <b>\"undefined\"</b>.</li></ol></li><li>If <var>val</var> has a [[Call]] internal method, return <b>\"function\"</b>.</li><li>Return <b>\"object\"</b>.</li></ol></emu-alg>\n      ","5.4":"<emu-note>\n        <p>The unary + operator converts its operand to Number type.</p>\n      </emu-note>\n\n      ","5.4.1":"<pre class=\"emu-grammar\">UnaryExpression : `+` UnaryExpression</pre>\n        <emu-alg><ol><li>Let <var>expr</var> be ? Evaluation of <emu-nt>UnaryExpression</emu-nt>.</li><li>Return ? ToNumber(? GetValue(<var>expr</var>)).</li></ol></emu-alg>\n      ","5.5":"<emu-note>\n        <p>The unary <code>-</code> operator converts its operand to a numeric value and then negates it. Negating <b>+0</b><sub>𝔽</sub> produces <b>-0</b><sub>𝔽</sub>, and negating <b>-0</b><sub>𝔽</sub> produces <b>+0</b><sub>𝔽</sub>.</p>\n      </emu-note>\n\n      ","5.5.1":"<pre class=\"emu-grammar\">UnaryExpression : `-` UnaryExpression</pre>\n        <emu-alg><ol><li>Let <var>expr</var> be ? Evaluation of <emu-nt>UnaryExpression</emu-nt>.</li><li>Let <var>oldValue</var> be ? ToNumeric(? GetValue(<var>expr</var>)).</li><li>If <var>oldValue</var> is a Number, return Number::unaryMinus(<var>oldValue</var>).</li><li>Assert: <var>oldValue</var> is a BigInt.</li><li>Return BigInt::unaryMinus(<var>oldValue</var>).</li></ol></emu-alg>\n      ","5.6":"","5.6.1":"<pre class=\"emu-grammar\">UnaryExpression : `~` UnaryExpression</pre>\n        <emu-alg><ol><li>Let <var>expr</var> be ? Evaluation of <emu-nt>UnaryExpression</emu-nt>.</li><li>Let <var>oldValue</var> be ? ToNumeric(? GetValue(<var>expr</var>)).</li><li>If <var>oldValue</var> is a Number, return Number::bitwiseNOT(<var>oldValue</var>).</li><li>Assert: <var>oldValue</var> is a BigInt.</li><li>Return BigInt::bitwiseNOT(<var>oldValue</var>).</li></ol></emu-alg>\n      ","5.7":"","5.7.1":"<pre class=\"emu-grammar\">UnaryExpression : `!` UnaryExpression</pre>\n        <emu-alg><ol><li>Let <var>expr</var> be ? Evaluation of <emu-nt>UnaryExpression</emu-nt>.</li><li>Let <var>oldValue</var> be ToBoolean(? GetValue(<var>expr</var>)).</li><li>If <var>oldValue</var> is <b>true</b>, return <b>false</b>.</li><li>Return <b>true</b>.</li></ol></emu-alg>\n      ","6.1":"<pre class=\"emu-grammar\">ExponentiationExpression : UpdateExpression `**` ExponentiationExpression</pre>\n      <emu-alg><ol><li>Return ? EvaluateStringOrNumericBinaryExpression(<emu-nt>UpdateExpression</emu-nt>, <code>**</code>, <emu-nt>ExponentiationExpression</emu-nt>).</li></ol></emu-alg>\n    ","7.1":"<pre class=\"emu-grammar\">MultiplicativeExpression : MultiplicativeExpression MultiplicativeOperator ExponentiationExpression</pre>\n      <emu-alg><ol><li>Let <var>opText</var> be the source text matched by <emu-nt>MultiplicativeOperator</emu-nt>.</li><li>Return ? EvaluateStringOrNumericBinaryExpression(<emu-nt>MultiplicativeExpression</emu-nt>, <var>opText</var>, <emu-nt>ExponentiationExpression</emu-nt>).</li></ol></emu-alg>\n    ","8.1":"<emu-note>\n        <p>The addition operator either performs string concatenation or numeric addition.</p>\n      </emu-note>\n\n      ","8.1.1":"<pre class=\"emu-grammar\">AdditiveExpression : AdditiveExpression `+` MultiplicativeExpression</pre>\n        <emu-alg><ol><li>Return ? EvaluateStringOrNumericBinaryExpression(<emu-nt>AdditiveExpression</emu-nt>, <code>+</code>, <emu-nt>MultiplicativeExpression</emu-nt>).</li></ol></emu-alg>\n      ","8.2":"<emu-note>\n        <p>The <code>-</code> operator performs subtraction, producing the difference of its operands.</p>\n      </emu-note>\n\n      ","8.2.1":"<pre class=\"emu-grammar\">AdditiveExpression : AdditiveExpression `-` MultiplicativeExpression</pre>\n        <emu-alg><ol><li>Return ? EvaluateStringOrNumericBinaryExpression(<emu-nt>AdditiveExpression</emu-nt>, <code>-</code>, <emu-nt>MultiplicativeExpression</emu-nt>).</li></ol></emu-alg>\n      ","9.1":"<emu-note>\n        <p>Performs a bitwise left shift operation on the left operand by the amount specified by the right operand.</p>\n      </emu-note>\n\n      ","9.1.1":"<pre class=\"emu-grammar\">ShiftExpression : ShiftExpression `&lt;&lt;` AdditiveExpression</pre>\n        <emu-alg><ol><li>Return ? EvaluateStringOrNumericBinaryExpression(<emu-nt>ShiftExpression</emu-nt>, <code>&lt;&lt;</code>, <emu-nt>AdditiveExpression</emu-nt>).</li></ol></emu-alg>\n      ","9.2":"<emu-note>\n        <p>Performs a sign-filling bitwise right shift operation on the left operand by the amount specified by the right operand.</p>\n      </emu-note>\n\n      ","9.2.1":"<pre class=\"emu-grammar\">ShiftExpression : ShiftExpression `&gt;&gt;` AdditiveExpression</pre>\n        <emu-alg><ol><li>Return ? EvaluateStringOrNumericBinaryExpression(<emu-nt>ShiftExpression</emu-nt>, <code>>></code>, <emu-nt>AdditiveExpression</emu-nt>).</li></ol></emu-alg>\n      ","9.3":"<emu-note>\n        <p>Performs a zero-filling bitwise right shift operation on the left operand by the amount specified by the right operand.</p>\n      </emu-note>\n\n      ","9.3.1":"<pre class=\"emu-grammar\">ShiftExpression : ShiftExpression `&gt;&gt;&gt;` AdditiveExpression</pre>\n        <emu-alg><ol><li>Return ? EvaluateStringOrNumericBinaryExpression(<emu-nt>ShiftExpression</emu-nt>, <code>>>></code>, <emu-nt>AdditiveExpression</emu-nt>).</li></ol></emu-alg>\n      ","10.1":"<pre class=\"emu-grammar\">RelationalExpression : RelationalExpression `&lt;` ShiftExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>RelationalExpression</emu-nt>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>ShiftExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li><li>Let <var>result</var> be ? IsLessThan(<var>lVal</var>, <var>rVal</var>, <b>true</b>).</li><li>If <var>result</var> is <b>undefined</b>, return <b>false</b>.</li><li>Return <var>result</var>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">RelationalExpression : RelationalExpression `&gt;` ShiftExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>RelationalExpression</emu-nt>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>ShiftExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li><li>Let <var>result</var> be ? IsLessThan(<var>rVal</var>, <var>lVal</var>, <b>false</b>).</li><li>If <var>result</var> is <b>undefined</b>, return <b>false</b>.</li><li>Return <var>result</var>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">RelationalExpression : RelationalExpression `&lt;=` ShiftExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>RelationalExpression</emu-nt>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>ShiftExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li><li>Let <var>result</var> be ? IsLessThan(<var>rVal</var>, <var>lVal</var>, <b>false</b>).</li><li>If <var>result</var> is either <b>true</b> or <b>undefined</b>, return <b>false</b>.</li><li>Return <b>true</b>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">RelationalExpression : RelationalExpression `&gt;=` ShiftExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>RelationalExpression</emu-nt>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>ShiftExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li><li>Let <var>result</var> be ? IsLessThan(<var>lVal</var>, <var>rVal</var>, <b>true</b>).</li><li>If <var>result</var> is either <b>true</b> or <b>undefined</b>, return <b>false</b>.</li><li>Return <b>true</b>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">RelationalExpression : RelationalExpression `instanceof` ShiftExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>RelationalExpression</emu-nt>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>ShiftExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li><li>Return ? InstanceofOperator(<var>lVal</var>, <var>rVal</var>).</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">RelationalExpression : RelationalExpression `in` ShiftExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>RelationalExpression</emu-nt>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>ShiftExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li><li>If <var>rVal</var> is not an Object, throw a <b>TypeError</b> exception.</li><li>Return ? HasProperty(<var>rVal</var>, ? ToPropertyKey(<var>lVal</var>)).</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">RelationalExpression : PrivateIdentifier `in` ShiftExpression</pre>\n      <emu-alg><ol><li>Let <var>privateIdentifier</var> be the StringValue of <emu-nt>PrivateIdentifier</emu-nt>.</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>ShiftExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li><li>If <var>rVal</var> is not an Object, throw a <b>TypeError</b> exception.</li><li>Let <var>privateEnv</var> be the running execution context's PrivateEnvironment.</li><li>Assert: <var>privateEnv</var> is not <b>null</b>.</li><li>Let <var>privateName</var> be ResolvePrivateIdentifier(<var>privateEnv</var>, <var>privateIdentifier</var>).</li><li>If PrivateElementFind(<var>rVal</var>, <var>privateName</var>) is <emu-const>empty</emu-const>, return <b>false</b>.</li><li>Return <b>true</b>.</li></ol></emu-alg>\n    ","10.2":"<dl class=\"header\">\n        <dt>description</dt>\n        <dd>It implements the generic algorithm for determining if <var>value</var> is an instance of <var>target</var> either by consulting <var>target</var>'s <code class=\"emu-intrinsic\">%Symbol.hasInstance%</code> method or, if absent, determining whether the value of <var>target</var>'s <b>\"prototype\"</b> property is present in <var>value</var>'s prototype chain.</dd>\n      </dl>\n      <emu-alg><ol><li>If <var>target</var> is not an Object, throw a <b>TypeError</b> exception.</li><li>Let <var>instOfHandler</var> be ? GetMethod(<var>target</var>, <code class=\"emu-intrinsic\">%Symbol.hasInstance%</code>).</li><li>If <var>instOfHandler</var> is not <b>undefined</b>, then<ol><li>Return ToBoolean(? Call(<var>instOfHandler</var>, <var>target</var>, « <var>value</var> »)).</li></ol></li><li>If IsCallable(<var>target</var>) is <b>false</b>, throw a <b>TypeError</b> exception.</li><li>Return ? OrdinaryHasInstance(<var>target</var>, <var>value</var>).</li></ol></emu-alg>\n      <emu-note>\n        <p>Steps step-instanceof-check-function and step-instanceof-fallback provide compatibility with previous editions of ECMAScript that did not use a <code class=\"emu-intrinsic\">%Symbol.hasInstance%</code> method to define the <code>instanceof</code> operator semantics. If an object does not define or inherit <code class=\"emu-intrinsic\">%Symbol.hasInstance%</code> it uses the default <code>instanceof</code> semantics.</p>\n      </emu-note>\n    ","11.1":"<pre class=\"emu-grammar\">EqualityExpression : EqualityExpression `==` RelationalExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>EqualityExpression</emu-nt>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>RelationalExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li><li>Return ? IsLooselyEqual(<var>rVal</var>, <var>lVal</var>).</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">EqualityExpression : EqualityExpression `!=` RelationalExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>EqualityExpression</emu-nt>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>RelationalExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li><li>Let <var>r</var> be ? IsLooselyEqual(<var>rVal</var>, <var>lVal</var>).</li><li>If <var>r</var> is <b>true</b>, return <b>false</b>.</li><li>Return <b>true</b>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">EqualityExpression : EqualityExpression `===` RelationalExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>EqualityExpression</emu-nt>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>RelationalExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li><li>Return IsStrictlyEqual(<var>rVal</var>, <var>lVal</var>).</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">EqualityExpression : EqualityExpression `!==` RelationalExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>EqualityExpression</emu-nt>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>RelationalExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li><li>Let <var>r</var> be IsStrictlyEqual(<var>rVal</var>, <var>lVal</var>).</li><li>If <var>r</var> is <b>true</b>, return <b>false</b>.</li><li>Return <b>true</b>.</li></ol></emu-alg>\n      <emu-note>\n        <p>The equality operators maintain the following invariants:</p>\n        <ul>\n          <li>\n            <code>A != B</code> is equivalent to <code>!(A == B)</code>.\n          </li>\n          <li>\n            <code>A == B</code> is equivalent to <code>B == A</code>, except in the order of evaluation of <code>A</code> and <code>B</code>.\n          </li>\n        </ul>\n      </emu-note>\n      <emu-note>\n        <p>The equality operator is not always transitive. For example, there might be two distinct String objects, each representing the same String value; each String object would be considered equal to the String value by the <code>==</code> operator, but the two String objects would not be equal to each other. For example:</p>\n        <ul>\n          <li>\n            <code>new String(\"a\") == \"a\"</code> and <code>\"a\" == new String(\"a\")</code> are both <b>true</b>.\n          </li>\n          <li>\n            <code>new String(\"a\") == new String(\"a\")</code> is <b>false</b>.\n          </li>\n        </ul>\n      </emu-note>\n      <emu-note>\n        <p>Comparison of Strings uses a simple equality test on sequences of code unit values. There is no attempt to use the more complex, semantically oriented definitions of character or string equality and collating order defined in the Unicode specification. Therefore Strings values that are canonically equal according to the Unicode Standard could test as unequal. In effect this algorithm assumes that both Strings are already in normalized form.</p>\n      </emu-note>\n    ","12.1":"<pre class=\"emu-grammar\">BitwiseANDExpression : BitwiseANDExpression `&amp;` EqualityExpression</pre>\n      <emu-alg><ol><li>Return ? EvaluateStringOrNumericBinaryExpression(<emu-nt>BitwiseANDExpression</emu-nt>, <code>&amp;</code>, <emu-nt>EqualityExpression</emu-nt>).</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">BitwiseXORExpression : BitwiseXORExpression `^` BitwiseANDExpression</pre>\n      <emu-alg><ol><li>Return ? EvaluateStringOrNumericBinaryExpression(<emu-nt>BitwiseXORExpression</emu-nt>, <code>^</code>, <emu-nt>BitwiseANDExpression</emu-nt>).</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">BitwiseORExpression : BitwiseORExpression `|` BitwiseXORExpression</pre>\n      <emu-alg><ol><li>Return ? EvaluateStringOrNumericBinaryExpression(<emu-nt>BitwiseORExpression</emu-nt>, <code>|</code>, <emu-nt>BitwiseXORExpression</emu-nt>).</li></ol></emu-alg>\n    ","13.1":"<pre class=\"emu-grammar\">LogicalANDExpression : LogicalANDExpression `&amp;&amp;` BitwiseORExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>LogicalANDExpression</emu-nt>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>If ToBoolean(<var>lVal</var>) is <b>false</b>, return <var>lVal</var>.</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>BitwiseORExpression</emu-nt>.</li><li>Return ? GetValue(<var>rRef</var>).</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">LogicalORExpression : LogicalORExpression `||` LogicalANDExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>LogicalORExpression</emu-nt>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>If ToBoolean(<var>lVal</var>) is <b>true</b>, return <var>lVal</var>.</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>LogicalANDExpression</emu-nt>.</li><li>Return ? GetValue(<var>rRef</var>).</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">CoalesceExpression : CoalesceExpressionHead `??` BitwiseORExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>CoalesceExpressionHead</emu-nt>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>If <var>lVal</var> is neither <b>undefined</b> nor <b>null</b>, return <var>lVal</var>.</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>BitwiseORExpression</emu-nt>.</li><li>Return ? GetValue(<var>rRef</var>).</li></ol></emu-alg>\n    ","14.1":"<pre class=\"emu-grammar\">ConditionalExpression : ShortCircuitExpression `?` AssignmentExpression `:` AssignmentExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>ShortCircuitExpression</emu-nt>.</li><li>Let <var>lVal</var> be ToBoolean(? GetValue(<var>lRef</var>)).</li><li>If <var>lVal</var> is <b>true</b>, then<ol><li>Let <var>trueRef</var> be ? Evaluation of the first <emu-nt>AssignmentExpression</emu-nt>.</li><li>Return ? GetValue(<var>trueRef</var>).</li></ol></li><li>Let <var>falseRef</var> be ? Evaluation of the second <emu-nt>AssignmentExpression</emu-nt>.</li><li>Return ? GetValue(<var>falseRef</var>).</li></ol></emu-alg>\n    ","15.1":"<pre class=\"emu-grammar\">AssignmentExpression : LeftHandSideExpression `=` AssignmentExpression</pre>\n      <ul>\n        <li>\n          If <emu-nt>LeftHandSideExpression</emu-nt> is either an <emu-nt>ObjectLiteral</emu-nt> or an <emu-nt>ArrayLiteral</emu-nt>, <emu-nt>LeftHandSideExpression</emu-nt> must cover an <emu-nt>AssignmentPattern</emu-nt>.\n        </li>\n        <li>\n          If <emu-nt>LeftHandSideExpression</emu-nt> is neither an <emu-nt>ObjectLiteral</emu-nt> nor an <emu-nt>ArrayLiteral</emu-nt>, it is a Syntax Error if the AssignmentTargetType of <emu-nt>LeftHandSideExpression</emu-nt> is <emu-const>invalid</emu-const>.\n        </li>\n      </ul>\n      <pre class=\"emu-grammar\">AssignmentExpression :\n  LeftHandSideExpression AssignmentOperator AssignmentExpression</pre>\n      <ul>\n        <li>\n          It is a Syntax Error if the AssignmentTargetType of <emu-nt>LeftHandSideExpression</emu-nt> is <emu-const>invalid</emu-const>.\n        </li>\n      </ul>\n      <pre class=\"emu-grammar\">AssignmentExpression :\n  LeftHandSideExpression `&amp;&amp;=` AssignmentExpression\n  LeftHandSideExpression `||=` AssignmentExpression\n  LeftHandSideExpression `??=` AssignmentExpression</pre>\n      <ul>\n        <li>\n          It is a Syntax Error if the AssignmentTargetType of <emu-nt>LeftHandSideExpression</emu-nt> is not <emu-const>simple</emu-const>.\n        </li>\n      </ul>\n    ","15.2":"<pre class=\"emu-grammar\">AssignmentExpression : LeftHandSideExpression `=` AssignmentExpression</pre>\n      <emu-alg><ol><li>If <emu-nt>LeftHandSideExpression</emu-nt> is neither an <emu-nt>ObjectLiteral</emu-nt> nor an <emu-nt>ArrayLiteral</emu-nt>, then<ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>LeftHandSideExpression</emu-nt>.</li><li>If the AssignmentTargetType of <emu-nt>LeftHandSideExpression</emu-nt> is <emu-const>web-compat</emu-const>, throw a <b>ReferenceError</b> exception.</li><li>If IsAnonymousFunctionDefinition(<emu-nt>AssignmentExpression</emu-nt>) is <b>true</b> and IsIdentifierRef of <emu-nt>LeftHandSideExpression</emu-nt> is <b>true</b>, then<ol><li>Let <var>lhs</var> be the StringValue of <emu-nt>LeftHandSideExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? NamedEvaluation of <emu-nt>AssignmentExpression</emu-nt> with argument <var>lhs</var>.</li></ol></li><li>Else,<ol><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li></ol></li><li>Perform ? PutValue(<var>lRef</var>, <var>rVal</var>).</li><li>Return <var>rVal</var>.</li></ol></li><li>Let <var>assignmentPattern</var> be the <emu-nt>AssignmentPattern</emu-nt> that is covered by <emu-nt>LeftHandSideExpression</emu-nt>.</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li><li>Perform ? DestructuringAssignmentEvaluation of <var>assignmentPattern</var> with argument <var>rVal</var>.</li><li>Return <var>rVal</var>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">AssignmentExpression : LeftHandSideExpression AssignmentOperator AssignmentExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>LeftHandSideExpression</emu-nt>.</li><li>If the AssignmentTargetType of <emu-nt>LeftHandSideExpression</emu-nt> is <emu-const>web-compat</emu-const>, throw a <b>ReferenceError</b> exception.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li><li>Let <var>assignmentOpText</var> be the source text matched by <emu-nt>AssignmentOperator</emu-nt>.</li><li>Let <var>opText</var> be the sequence of Unicode code points associated with <var>assignmentOpText</var> in the following table:\n          <figure>\n            <!-- emu-format ignore -->\n            <table class=\"lightweight-table\">\n              <thead>\n                <tr><th> <var>assignmentOpText</var> </th><th> <var>opText</var>       </th></tr>\n              </thead>\n              <tr><td> <code>**=</code>              </td><td> <code>**</code>           </td></tr>\n              <tr><td> <code>*=</code>               </td><td> <code>*</code>            </td></tr>\n              <tr><td> <code>/=</code>               </td><td> <code>/</code>            </td></tr>\n              <tr><td> <code>%=</code>               </td><td> <code>%</code>            </td></tr>\n              <tr><td> <code>+=</code>               </td><td> <code>+</code>            </td></tr>\n              <tr><td> <code>-=</code>               </td><td> <code>-</code>            </td></tr>\n              <tr><td> <code>&lt;&lt;=</code>        </td><td> <code>&lt;&lt;</code>     </td></tr>\n              <tr><td> <code>&gt;&gt;=</code>        </td><td> <code>&gt;&gt;</code>     </td></tr>\n              <tr><td> <code>&gt;&gt;&gt;=</code>    </td><td> <code>&gt;&gt;&gt;</code> </td></tr>\n              <tr><td> <code>&amp;=</code>           </td><td> <code>&amp;</code>        </td></tr>\n              <tr><td> <code>^=</code>               </td><td> <code>^</code>            </td></tr>\n              <tr><td> <code>|=</code>               </td><td> <code>|</code>            </td></tr>\n            </table>\n          </figure></li><li>Let <var>r</var> be ? ApplyStringOrNumericBinaryOperator(<var>lVal</var>, <var>opText</var>, <var>rVal</var>).</li><li>Perform ? PutValue(<var>lRef</var>, <var>r</var>).</li><li>Return <var>r</var>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">AssignmentExpression : LeftHandSideExpression `&amp;&amp;=` AssignmentExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>LeftHandSideExpression</emu-nt>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>If ToBoolean(<var>lVal</var>) is <b>false</b>, return <var>lVal</var>.</li><li>If IsAnonymousFunctionDefinition(<emu-nt>AssignmentExpression</emu-nt>) is <b>true</b> and IsIdentifierRef of <emu-nt>LeftHandSideExpression</emu-nt> is <b>true</b>, then<ol><li>Let <var>lhs</var> be the StringValue of <emu-nt>LeftHandSideExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? NamedEvaluation of <emu-nt>AssignmentExpression</emu-nt> with argument <var>lhs</var>.</li></ol></li><li>Else,<ol><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li></ol></li><li>Perform ? PutValue(<var>lRef</var>, <var>rVal</var>).</li><li>Return <var>rVal</var>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">AssignmentExpression : LeftHandSideExpression `||=` AssignmentExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>LeftHandSideExpression</emu-nt>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>If ToBoolean(<var>lVal</var>) is <b>true</b>, return <var>lVal</var>.</li><li>If IsAnonymousFunctionDefinition(<emu-nt>AssignmentExpression</emu-nt>) is <b>true</b> and IsIdentifierRef of <emu-nt>LeftHandSideExpression</emu-nt> is <b>true</b>, then<ol><li>Let <var>lhs</var> be the StringValue of <emu-nt>LeftHandSideExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? NamedEvaluation of <emu-nt>AssignmentExpression</emu-nt> with argument <var>lhs</var>.</li></ol></li><li>Else,<ol><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li></ol></li><li>Perform ? PutValue(<var>lRef</var>, <var>rVal</var>).</li><li>Return <var>rVal</var>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\">AssignmentExpression : LeftHandSideExpression `??=` AssignmentExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>LeftHandSideExpression</emu-nt>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>If <var>lVal</var> is neither <b>undefined</b> nor <b>null</b>, return <var>lVal</var>.</li><li>If IsAnonymousFunctionDefinition(<emu-nt>AssignmentExpression</emu-nt>) is <b>true</b> and IsIdentifierRef of <emu-nt>LeftHandSideExpression</emu-nt> is <b>true</b>, then<ol><li>Let <var>lhs</var> be the StringValue of <emu-nt>LeftHandSideExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? NamedEvaluation of <emu-nt>AssignmentExpression</emu-nt> with argument <var>lhs</var>.</li></ol></li><li>Else,<ol><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li></ol></li><li>Perform ? PutValue(<var>lRef</var>, <var>rVal</var>).</li><li>Return <var>rVal</var>.</li></ol></emu-alg>\n      <emu-note>\n        <p>When this expression occurs within strict mode code, it is a runtime error if <var>lRef</var> in step step-assignmentexpression-evaluation-simple-putvalue, step-assignmentexpression-evaluation-compound-getvalue, step-assignmentexpression-evaluation-lgcl-and-getvalue, step-assignmentexpression-evaluation-lgcl-or-getvalue, step-assignmentexpression-evaluation-lgcl-nullish-getvalue is an unresolvable reference. If it is, a <b>ReferenceError</b> exception is thrown. Additionally, it is a runtime error if the <var>lRef</var> in step step-assignmentexpression-evaluation-compound-putvalue, step-assignmentexpression-evaluation-lgcl-and-putvalue, step-assignmentexpression-evaluation-lgcl-or-putvalue, step-assignmentexpression-evaluation-lgcl-nullish-putvalue is a reference to a data property with the attribute value { [[Writable]]: <b>false</b> }, to an accessor property with the attribute value { [[Set]]: <b>undefined</b> }, or to a non-existent property of an object for which the IsExtensible predicate returns the value <b>false</b>. In these cases a <b>TypeError</b> exception is thrown.</p>\n      </emu-note>\n    ","15.3":"<dl class=\"header\">\n      </dl>\n      <emu-alg><ol><li>If <var>opText</var> is <code>+</code>, then<ol><li>Let <var>lPrim</var> be ? ToPrimitive(<var>lVal</var>).</li><li>Let <var>rPrim</var> be ? ToPrimitive(<var>rVal</var>).</li><li>If <var>lPrim</var> is a String or <var>rPrim</var> is a String, then<ol><li>Let <var>lStr</var> be ? ToString(<var>lPrim</var>).</li><li>Let <var>rStr</var> be ? ToString(<var>rPrim</var>).</li><li>Return the string-concatenation of <var>lStr</var> and <var>rStr</var>.</li></ol></li><li>Set <var>lVal</var> to <var>lPrim</var>.</li><li>Set <var>rVal</var> to <var>rPrim</var>.</li></ol></li><li>NOTE: At this point, it must be a numeric operation.</li><li>Let <var>lNum</var> be ? ToNumeric(<var>lVal</var>).</li><li>Let <var>rNum</var> be ? ToNumeric(<var>rVal</var>).</li><li>If SameType(<var>lNum</var>, <var>rNum</var>) is <b>false</b>, throw a <b>TypeError</b> exception.</li><li>If <var>lNum</var> is a BigInt, then<ol><li>If <var>opText</var> is <code>**</code>, return ? BigInt::exponentiate(<var>lNum</var>, <var>rNum</var>).</li><li>If <var>opText</var> is <code>/</code>, return ? BigInt::divide(<var>lNum</var>, <var>rNum</var>).</li><li>If <var>opText</var> is <code>%</code>, return ? BigInt::remainder(<var>lNum</var>, <var>rNum</var>).</li><li>If <var>opText</var> is <code>>>></code>, return ? BigInt::unsignedRightShift(<var>lNum</var>, <var>rNum</var>).</li><li>Let <var>operation</var> be the abstract operation associated with <var>opText</var> in the following table:\n            <figure>\n              <!-- emu-format ignore -->\n              <table class=\"lightweight-table\">\n                <thead>\n                  <tr><th> <var>opText</var>   </th><th> <var>operation</var>              </th></tr>\n                </thead>\n                <tbody>\n                  <tr><td> <code>*</code>        </td><td> BigInt::multiply         </td></tr>\n                  <tr><td> <code>+</code>        </td><td> BigInt::add              </td></tr>\n                  <tr><td> <code>-</code>        </td><td> BigInt::subtract         </td></tr>\n                  <tr><td> <code>&lt;&lt;</code> </td><td> BigInt::leftShift        </td></tr>\n                  <tr><td> <code>&gt;&gt;</code> </td><td> BigInt::signedRightShift </td></tr>\n                  <tr><td> <code>&amp;</code>    </td><td> BigInt::bitwiseAND       </td></tr>\n                  <tr><td> <code>^</code>        </td><td> BigInt::bitwiseXOR       </td></tr>\n                  <tr><td> <code>|</code>        </td><td> BigInt::bitwiseOR        </td></tr>\n                </tbody>\n              </table>\n            </figure></li></ol></li><li>Else,<ol><li>Assert: <var>lNum</var> is a Number.</li><li>Let <var>operation</var> be the abstract operation associated with <var>opText</var> in the following table:\n            <figure>\n              <!-- emu-format ignore -->\n              <table class=\"lightweight-table\">\n                <thead>\n                  <tr><th> <var>opText</var>       </th><th> <var>operation</var>                </th></tr>\n                </thead>\n                <tbody>\n                  <tr><td> <code>**</code>           </td><td> Number::exponentiate       </td></tr>\n                  <tr><td> <code>*</code>            </td><td> Number::multiply           </td></tr>\n                  <tr><td> <code>/</code>            </td><td> Number::divide             </td></tr>\n                  <tr><td> <code>%</code>            </td><td> Number::remainder          </td></tr>\n                  <tr><td> <code>+</code>            </td><td> Number::add                </td></tr>\n                  <tr><td> <code>-</code>            </td><td> Number::subtract           </td></tr>\n                  <tr><td> <code>&lt;&lt;</code>     </td><td> Number::leftShift          </td></tr>\n                  <tr><td> <code>&gt;&gt;</code>     </td><td> Number::signedRightShift   </td></tr>\n                  <tr><td> <code>&gt;&gt;&gt;</code> </td><td> Number::unsignedRightShift </td></tr>\n                  <tr><td> <code>&amp;</code>        </td><td> Number::bitwiseAND         </td></tr>\n                  <tr><td> <code>^</code>            </td><td> Number::bitwiseXOR         </td></tr>\n                  <tr><td> <code>|</code>            </td><td> Number::bitwiseOR          </td></tr>\n                </tbody>\n              </table>\n            </figure></li></ol></li><li>Return <var>operation</var>(<var>lNum</var>, <var>rNum</var>).</li></ol></emu-alg>\n      <emu-note>\n        <p>No hint is provided in the calls to ToPrimitive in steps step-binary-op-toprimitive-lval and step-binary-op-toprimitive-rval. All standard objects except Dates handle the absence of a hint as if <emu-const>number</emu-const> were given; Dates handle the absence of a hint as if <emu-const>string</emu-const> were given. Exotic objects may handle the absence of a hint in some other manner.</p>\n      </emu-note>\n      <emu-note>\n        <p>Step step-binary-op-string-check differs from step step-arc-string-check of the IsLessThan algorithm, by using the logical-or operation instead of the logical-and operation.</p>\n      </emu-note>\n    ","15.4":"<dl class=\"header\">\n      </dl>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <var>leftOperand</var>.</li><li>Let <var>lVal</var> be ? GetValue(<var>lRef</var>).</li><li>Let <var>rRef</var> be ? Evaluation of <var>rightOperand</var>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rRef</var>).</li><li>Return ? ApplyStringOrNumericBinaryOperator(<var>lVal</var>, <var>opText</var>, <var>rVal</var>).</li></ol></emu-alg>\n    ","15.5":"<h2>Supplemental Syntax</h2>\n      <p>\n        In certain circumstances when processing an instance of the production<br>\n        <pre class=\"emu-grammar\">AssignmentExpression : LeftHandSideExpression `=` AssignmentExpression</pre><br>\n        the interpretation of <emu-nt>LeftHandSideExpression</emu-nt> is refined using the following grammar:\n      </p>\n      <pre class=\"emu-grammar\">AssignmentPattern[Yield, Await] :\n  ObjectAssignmentPattern[?Yield, ?Await]\n  ArrayAssignmentPattern[?Yield, ?Await]\n\nObjectAssignmentPattern[Yield, Await] :\n  `{` `}`\n  `{` AssignmentRestProperty[?Yield, ?Await] `}`\n  `{` AssignmentPropertyList[?Yield, ?Await] `}`\n  `{` AssignmentPropertyList[?Yield, ?Await] `,` AssignmentRestProperty[?Yield, ?Await]? `}`\n\nArrayAssignmentPattern[Yield, Await] :\n  `[` Elision? AssignmentRestElement[?Yield, ?Await]? `]`\n  `[` AssignmentElementList[?Yield, ?Await] `]`\n  `[` AssignmentElementList[?Yield, ?Await] `,` Elision? AssignmentRestElement[?Yield, ?Await]? `]`\n\nAssignmentRestProperty[Yield, Await] :\n  `...` DestructuringAssignmentTarget[?Yield, ?Await]\n\nAssignmentPropertyList[Yield, Await] :\n  AssignmentProperty[?Yield, ?Await]\n  AssignmentPropertyList[?Yield, ?Await] `,` AssignmentProperty[?Yield, ?Await]\n\nAssignmentElementList[Yield, Await] :\n  AssignmentElisionElement[?Yield, ?Await]\n  AssignmentElementList[?Yield, ?Await] `,` AssignmentElisionElement[?Yield, ?Await]\n\nAssignmentElisionElement[Yield, Await] :\n  Elision? AssignmentElement[?Yield, ?Await]\n\nAssignmentProperty[Yield, Await] :\n  IdentifierReference[?Yield, ?Await] Initializer[+In, ?Yield, ?Await]?\n  PropertyName[?Yield, ?Await] `:` AssignmentElement[?Yield, ?Await]\n\nAssignmentElement[Yield, Await] :\n  DestructuringAssignmentTarget[?Yield, ?Await] Initializer[+In, ?Yield, ?Await]?\n\nAssignmentRestElement[Yield, Await] :\n  `...` DestructuringAssignmentTarget[?Yield, ?Await]\n\nDestructuringAssignmentTarget[Yield, Await] :\n  LeftHandSideExpression[?Yield, ?Await]</pre>\n\n      ","15.5.1":"<pre class=\"emu-grammar\">AssignmentProperty : IdentifierReference Initializer?</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if the AssignmentTargetType of <emu-nt>IdentifierReference</emu-nt> is not <emu-const>simple</emu-const>.\n          </li>\n        </ul>\n        <pre class=\"emu-grammar\">AssignmentRestProperty : `...` DestructuringAssignmentTarget</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if <emu-nt>DestructuringAssignmentTarget</emu-nt> is either an <emu-nt>ArrayLiteral</emu-nt> or an <emu-nt>ObjectLiteral</emu-nt>.\n          </li>\n        </ul>\n        <pre class=\"emu-grammar\">DestructuringAssignmentTarget : LeftHandSideExpression</pre>\n        <ul>\n          <li>\n            If <emu-nt>LeftHandSideExpression</emu-nt> is either an <emu-nt>ObjectLiteral</emu-nt> or an <emu-nt>ArrayLiteral</emu-nt>, <emu-nt>LeftHandSideExpression</emu-nt> must cover an <emu-nt>AssignmentPattern</emu-nt>.\n          </li>\n          <li>\n            If <emu-nt>LeftHandSideExpression</emu-nt> is neither an <emu-nt>ObjectLiteral</emu-nt> nor an <emu-nt>ArrayLiteral</emu-nt>, it is a Syntax Error if the AssignmentTargetType of <emu-nt>LeftHandSideExpression</emu-nt> is not <emu-const>simple</emu-const>.\n          </li>\n        </ul>\n      ","15.5.2":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">ObjectAssignmentPattern : `{` `}`</pre>\n        <emu-alg><ol><li>Perform ? RequireObjectCoercible(<var>value</var>).</li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ObjectAssignmentPattern :\n  `{` AssignmentPropertyList `}`\n  `{` AssignmentPropertyList `,` `}`</pre>\n        <emu-alg><ol><li>Perform ? RequireObjectCoercible(<var>value</var>).</li><li>Perform ? PropertyDestructuringAssignmentEvaluation of <emu-nt>AssignmentPropertyList</emu-nt> with argument <var>value</var>.</li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ObjectAssignmentPattern : `{` AssignmentRestProperty `}`</pre>\n        <emu-alg><ol><li>Perform ? RequireObjectCoercible(<var>value</var>).</li><li>Let <var>excludedNames</var> be a new empty List.</li><li>Return ? RestDestructuringAssignmentEvaluation of <emu-nt>AssignmentRestProperty</emu-nt> with arguments <var>value</var> and <var>excludedNames</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ObjectAssignmentPattern : `{` AssignmentPropertyList `,` AssignmentRestProperty `}`</pre>\n        <emu-alg><ol><li>Perform ? RequireObjectCoercible(<var>value</var>).</li><li>Let <var>excludedNames</var> be ? PropertyDestructuringAssignmentEvaluation of <emu-nt>AssignmentPropertyList</emu-nt> with argument <var>value</var>.</li><li>Return ? RestDestructuringAssignmentEvaluation of <emu-nt>AssignmentRestProperty</emu-nt> with arguments <var>value</var> and <var>excludedNames</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ArrayAssignmentPattern : `[` `]`</pre>\n        <emu-alg><ol><li>Let <var>iteratorRecord</var> be ? GetIterator(<var>value</var>, <emu-const>sync</emu-const>).</li><li>Return ? IteratorClose(<var>iteratorRecord</var>, NormalCompletion(<emu-const>unused</emu-const>)).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ArrayAssignmentPattern : `[` Elision `]`</pre>\n        <emu-alg><ol><li>Let <var>iteratorRecord</var> be ? GetIterator(<var>value</var>, <emu-const>sync</emu-const>).</li><li>Let <var>result</var> be Completion(IteratorDestructuringAssignmentEvaluation of <emu-nt>Elision</emu-nt> with argument <var>iteratorRecord</var>).</li><li>If <var>iteratorRecord</var>.[[Done]] is <b>false</b>, return ? IteratorClose(<var>iteratorRecord</var>, <var>result</var>).</li><li>Return <var>result</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ArrayAssignmentPattern : `[` Elision? AssignmentRestElement `]`</pre>\n        <emu-alg><ol><li>Let <var>iteratorRecord</var> be ? GetIterator(<var>value</var>, <emu-const>sync</emu-const>).</li><li>If <emu-nt>Elision</emu-nt> is present, then<ol><li>Let <var>status</var> be Completion(IteratorDestructuringAssignmentEvaluation of <emu-nt>Elision</emu-nt> with argument <var>iteratorRecord</var>).</li><li>If <var>status</var> is an abrupt completion, then<ol><li>Assert: <var>iteratorRecord</var>.[[Done]] is <b>true</b>.</li><li>Return ? <var>status</var>.</li></ol></li></ol></li><li>Let <var>result</var> be Completion(IteratorDestructuringAssignmentEvaluation of <emu-nt>AssignmentRestElement</emu-nt> with argument <var>iteratorRecord</var>).</li><li>If <var>iteratorRecord</var>.[[Done]] is <b>false</b>, return ? IteratorClose(<var>iteratorRecord</var>, <var>result</var>).</li><li>Return <var>result</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ArrayAssignmentPattern : `[` AssignmentElementList `]`</pre>\n        <emu-alg><ol><li>Let <var>iteratorRecord</var> be ? GetIterator(<var>value</var>, <emu-const>sync</emu-const>).</li><li>Let <var>result</var> be Completion(IteratorDestructuringAssignmentEvaluation of <emu-nt>AssignmentElementList</emu-nt> with argument <var>iteratorRecord</var>).</li><li>If <var>iteratorRecord</var>.[[Done]] is <b>false</b>, return ? IteratorClose(<var>iteratorRecord</var>, <var>result</var>).</li><li>Return <var>result</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ArrayAssignmentPattern : `[` AssignmentElementList `,` Elision? AssignmentRestElement? `]`</pre>\n        <emu-alg><ol><li>Let <var>iteratorRecord</var> be ? GetIterator(<var>value</var>, <emu-const>sync</emu-const>).</li><li>Let <var>status</var> be Completion(IteratorDestructuringAssignmentEvaluation of <emu-nt>AssignmentElementList</emu-nt> with argument <var>iteratorRecord</var>).</li><li>If <var>status</var> is an abrupt completion, then<ol><li>If <var>iteratorRecord</var>.[[Done]] is <b>false</b>, return ? IteratorClose(<var>iteratorRecord</var>, <var>status</var>).</li><li>Return ? <var>status</var>.</li></ol></li><li>If <emu-nt>Elision</emu-nt> is present, then<ol><li>Set <var>status</var> to Completion(IteratorDestructuringAssignmentEvaluation of <emu-nt>Elision</emu-nt> with argument <var>iteratorRecord</var>).</li><li>If <var>status</var> is an abrupt completion, then<ol><li>Assert: <var>iteratorRecord</var>.[[Done]] is <b>true</b>.</li><li>Return ? <var>status</var>.</li></ol></li></ol></li><li>If <emu-nt>AssignmentRestElement</emu-nt> is present, then<ol><li>Set <var>status</var> to Completion(IteratorDestructuringAssignmentEvaluation of <emu-nt>AssignmentRestElement</emu-nt> with argument <var>iteratorRecord</var>).</li></ol></li><li>If <var>iteratorRecord</var>.[[Done]] is <b>false</b>, return ? IteratorClose(<var>iteratorRecord</var>, <var>status</var>).</li><li>Return ? <var>status</var>.</li></ol></emu-alg>\n      ","15.5.3":"<dl class=\"header\">\n          <dt>description</dt>\n          <dd>It collects a list of all destructured property keys.</dd>\n        </dl>\n        <pre class=\"emu-grammar\">AssignmentPropertyList : AssignmentPropertyList `,` AssignmentProperty</pre>\n        <emu-alg><ol><li>Let <var>propertyNames</var> be ? PropertyDestructuringAssignmentEvaluation of <emu-nt>AssignmentPropertyList</emu-nt> with argument <var>value</var>.</li><li>Let <var>nextNames</var> be ? PropertyDestructuringAssignmentEvaluation of <emu-nt>AssignmentProperty</emu-nt> with argument <var>value</var>.</li><li>Return the list-concatenation of <var>propertyNames</var> and <var>nextNames</var>.</li></ol></emu-alg>\n\n        <pre class=\"emu-grammar\">AssignmentProperty : IdentifierReference Initializer?</pre>\n        <emu-alg><ol><li>Let <var>propertyName</var> be the StringValue of <emu-nt>IdentifierReference</emu-nt>.</li><li>Let <var>lRef</var> be ? ResolveBinding(<var>propertyName</var>).</li><li>Let <var>v</var> be ? GetV(<var>value</var>, <var>propertyName</var>).</li><li>If <emu-nt>Initializer</emu-nt> is present and <var>v</var> is <b>undefined</b>, then<ol><li>If IsAnonymousFunctionDefinition(<emu-nt>Initializer</emu-nt>) is <b>true</b>, then<ol><li>Set <var>v</var> to ? NamedEvaluation of <emu-nt>Initializer</emu-nt> with argument <var>propertyName</var>.</li></ol></li><li>Else,<ol><li>Let <var>defaultValue</var> be ? Evaluation of <emu-nt>Initializer</emu-nt>.</li><li>Set <var>v</var> to ? GetValue(<var>defaultValue</var>).</li></ol></li></ol></li><li>Perform ? PutValue(<var>lRef</var>, <var>v</var>).</li><li>Return « <var>propertyName</var> ».</li></ol></emu-alg>\n\n        <pre class=\"emu-grammar\">AssignmentProperty : PropertyName `:` AssignmentElement</pre>\n        <emu-alg><ol><li>Let <var>name</var> be ? Evaluation of <emu-nt>PropertyName</emu-nt>.</li><li>Perform ? KeyedDestructuringAssignmentEvaluation of <emu-nt>AssignmentElement</emu-nt> with arguments <var>value</var> and <var>name</var>.</li><li>Return « <var>name</var> ».</li></ol></emu-alg>\n      ","15.5.4":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">AssignmentRestProperty : `...` DestructuringAssignmentTarget</pre>\n        <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>DestructuringAssignmentTarget</emu-nt>.</li><li>Let <var>restObj</var> be OrdinaryObjectCreate(<code class=\"emu-intrinsic\">%Object.prototype%</code>).</li><li>Perform ? CopyDataProperties(<var>restObj</var>, <var>value</var>, <var>excludedNames</var>).</li><li>Return ? PutValue(<var>lRef</var>, <var>restObj</var>).</li></ol></emu-alg>\n      ","15.5.5":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">AssignmentElementList : AssignmentElisionElement</pre>\n        <emu-alg><ol><li>Return ? IteratorDestructuringAssignmentEvaluation of <emu-nt>AssignmentElisionElement</emu-nt> with argument <var>iteratorRecord</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">AssignmentElementList : AssignmentElementList `,` AssignmentElisionElement</pre>\n        <emu-alg><ol><li>Perform ? IteratorDestructuringAssignmentEvaluation of <emu-nt>AssignmentElementList</emu-nt> with argument <var>iteratorRecord</var>.</li><li>Return ? IteratorDestructuringAssignmentEvaluation of <emu-nt>AssignmentElisionElement</emu-nt> with argument <var>iteratorRecord</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">AssignmentElisionElement : AssignmentElement</pre>\n        <emu-alg><ol><li>Return ? IteratorDestructuringAssignmentEvaluation of <emu-nt>AssignmentElement</emu-nt> with argument <var>iteratorRecord</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">AssignmentElisionElement : Elision AssignmentElement</pre>\n        <emu-alg><ol><li>Perform ? IteratorDestructuringAssignmentEvaluation of <emu-nt>Elision</emu-nt> with argument <var>iteratorRecord</var>.</li><li>Return ? IteratorDestructuringAssignmentEvaluation of <emu-nt>AssignmentElement</emu-nt> with argument <var>iteratorRecord</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">Elision : `,`</pre>\n        <emu-alg><ol><li>If <var>iteratorRecord</var>.[[Done]] is <b>false</b>, then<ol><li>Perform ? IteratorStep(<var>iteratorRecord</var>).</li></ol></li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">Elision : Elision `,`</pre>\n        <emu-alg><ol><li>Perform ? IteratorDestructuringAssignmentEvaluation of <emu-nt>Elision</emu-nt> with argument <var>iteratorRecord</var>.</li><li>If <var>iteratorRecord</var>.[[Done]] is <b>false</b>, then<ol><li>Perform ? IteratorStep(<var>iteratorRecord</var>).</li></ol></li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">AssignmentElement : DestructuringAssignmentTarget Initializer?</pre>\n        <emu-alg><ol><li>If <emu-nt>DestructuringAssignmentTarget</emu-nt> is neither an <emu-nt>ObjectLiteral</emu-nt> nor an <emu-nt>ArrayLiteral</emu-nt>, then<ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>DestructuringAssignmentTarget</emu-nt>.</li></ol></li><li>Let <var>value</var> be <b>undefined</b>.</li><li>If <var>iteratorRecord</var>.[[Done]] is <b>false</b>, then<ol><li>Let <var>next</var> be ? IteratorStepValue(<var>iteratorRecord</var>).</li><li>If <var>next</var> is not <emu-const>done</emu-const>, then<ol><li>Set <var>value</var> to <var>next</var>.</li></ol></li></ol></li><li>If <emu-nt>Initializer</emu-nt> is present and <var>value</var> is <b>undefined</b>, then<ol><li>If IsAnonymousFunctionDefinition(<emu-nt>Initializer</emu-nt>) is <b>true</b> and IsIdentifierRef of <emu-nt>DestructuringAssignmentTarget</emu-nt> is <b>true</b>, then<ol><li>Let <var>target</var> be the StringValue of <emu-nt>DestructuringAssignmentTarget</emu-nt>.</li><li>Let <var>v</var> be ? NamedEvaluation of <emu-nt>Initializer</emu-nt> with argument <var>target</var>.</li></ol></li><li>Else,<ol><li>Let <var>defaultValue</var> be ? Evaluation of <emu-nt>Initializer</emu-nt>.</li><li>Let <var>v</var> be ? GetValue(<var>defaultValue</var>).</li></ol></li></ol></li><li>Else,<ol><li>Let <var>v</var> be <var>value</var>.</li></ol></li><li>If <emu-nt>DestructuringAssignmentTarget</emu-nt> is either an <emu-nt>ObjectLiteral</emu-nt> or an <emu-nt>ArrayLiteral</emu-nt>, then<ol><li>Let <var>nestedAssignmentPattern</var> be the <emu-nt>AssignmentPattern</emu-nt> that is covered by <emu-nt>DestructuringAssignmentTarget</emu-nt>.</li><li>Return ? DestructuringAssignmentEvaluation of <var>nestedAssignmentPattern</var> with argument <var>v</var>.</li></ol></li><li>Return ? PutValue(<var>lRef</var>, <var>v</var>).</li></ol></emu-alg>\n        <emu-note>\n          <p>Left to right evaluation order is maintained by evaluating a <emu-nt>DestructuringAssignmentTarget</emu-nt> that is not a destructuring pattern prior to accessing the iterator or evaluating the <emu-nt>Initializer</emu-nt>.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\">AssignmentRestElement : `...` DestructuringAssignmentTarget</pre>\n        <emu-alg><ol><li>If <emu-nt>DestructuringAssignmentTarget</emu-nt> is neither an <emu-nt>ObjectLiteral</emu-nt> nor an <emu-nt>ArrayLiteral</emu-nt>, then<ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>DestructuringAssignmentTarget</emu-nt>.</li></ol></li><li>Let <var>array</var> be ! ArrayCreate(0).</li><li>Let <var>n</var> be 0.</li><li>Repeat, while <var>iteratorRecord</var>.[[Done]] is <b>false</b>,<ol><li>Let <var>next</var> be ? IteratorStepValue(<var>iteratorRecord</var>).</li><li>If <var>next</var> is not <emu-const>done</emu-const>, then<ol><li>Perform ! CreateDataPropertyOrThrow(<var>array</var>, ! ToString(𝔽(<var>n</var>)), <var>next</var>).</li><li>Set <var>n</var> to <var>n</var> + 1.</li></ol></li></ol></li><li>If <emu-nt>DestructuringAssignmentTarget</emu-nt> is neither an <emu-nt>ObjectLiteral</emu-nt> nor an <emu-nt>ArrayLiteral</emu-nt>, then<ol><li>Return ? PutValue(<var>lRef</var>, <var>array</var>).</li></ol></li><li>Let <var>nestedAssignmentPattern</var> be the <emu-nt>AssignmentPattern</emu-nt> that is covered by <emu-nt>DestructuringAssignmentTarget</emu-nt>.</li><li>Return ? DestructuringAssignmentEvaluation of <var>nestedAssignmentPattern</var> with argument <var>array</var>.</li></ol></emu-alg>\n      ","15.5.6":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">AssignmentElement : DestructuringAssignmentTarget Initializer?</pre>\n        <emu-alg><ol><li>If <emu-nt>DestructuringAssignmentTarget</emu-nt> is neither an <emu-nt>ObjectLiteral</emu-nt> nor an <emu-nt>ArrayLiteral</emu-nt>, then<ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>DestructuringAssignmentTarget</emu-nt>.</li></ol></li><li>Let <var>v</var> be ? GetV(<var>value</var>, <var>propertyName</var>).</li><li>If <emu-nt>Initializer</emu-nt> is present and <var>v</var> is <b>undefined</b>, then<ol><li>If IsAnonymousFunctionDefinition(<emu-nt>Initializer</emu-nt>) is <b>true</b> and IsIdentifierRef of <emu-nt>DestructuringAssignmentTarget</emu-nt> is <b>true</b>, then<ol><li>Let <var>target</var> be the StringValue of <emu-nt>DestructuringAssignmentTarget</emu-nt>.</li><li>Let <var>rhsValue</var> be ? NamedEvaluation of <emu-nt>Initializer</emu-nt> with argument <var>target</var>.</li></ol></li><li>Else,<ol><li>Let <var>defaultValue</var> be ? Evaluation of <emu-nt>Initializer</emu-nt>.</li><li>Let <var>rhsValue</var> be ? GetValue(<var>defaultValue</var>).</li></ol></li></ol></li><li>Else,<ol><li>Let <var>rhsValue</var> be <var>v</var>.</li></ol></li><li>If <emu-nt>DestructuringAssignmentTarget</emu-nt> is either an <emu-nt>ObjectLiteral</emu-nt> or an <emu-nt>ArrayLiteral</emu-nt>, then<ol><li>Let <var>assignmentPattern</var> be the <emu-nt>AssignmentPattern</emu-nt> that is covered by <emu-nt>DestructuringAssignmentTarget</emu-nt>.</li><li>Return ? DestructuringAssignmentEvaluation of <var>assignmentPattern</var> with argument <var>rhsValue</var>.</li></ol></li><li>Return ? PutValue(<var>lRef</var>, <var>rhsValue</var>).</li></ol></emu-alg>\n      ","16.1":"<pre class=\"emu-grammar\">Expression : Expression `,` AssignmentExpression</pre>\n      <emu-alg><ol><li>Let <var>lRef</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Perform ? GetValue(<var>lRef</var>).</li><li>Let <var>rRef</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Return ? GetValue(<var>rRef</var>).</li></ol></emu-alg>\n      <emu-note>\n        <p>GetValue must be called even though its value is not used because it may have observable side-effects.</p>\n      </emu-note>\n    "};
const _basePath = process.env.NEXT_PUBLIC_BASE_PATH || '';
const sections = _basePath
  ? Object.fromEntries(
      Object.entries(_sections).map(([k, v]) => [
        k,
        v.replaceAll('href="/', `href="${_basePath}/`),
      ])
    )
  : _sections;
export function Sec({ id }) {
  const html = sections[id] ?? '';
  return <div className="ecma-spec" dangerouslySetInnerHTML={{ __html: html }} />;
}
